  1→// agent-server/index.ts
  2→// Entry point for the Deus agent-server process.
  3→//
  4→// Supports two transport modes (selected via --listen flag):
  5→//   --listen ws://    → WebSocket server on 127.0.0.1 (default, dynamic port)
  6→//   --listen unix://  → Unix domain socket (legacy, for backward compat)
  7→//
  8→// Both transports use JSON-RPC 2.0 over text frames/lines.
  9→
 10→import * as Sentry from "@sentry/node";
 11→
 12→// Initialize Sentry before anything else.
 13→// DSN passed as env var from Electron main process (not hardcoded — open source repo).
 14→if (process.env.SENTRY_DSN) {
 15→  Sentry.init({
 16→    dsn: process.env.SENTRY_DSN,
 17→    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 18→    sendDefaultPii: true,
 19→    initialScope: { tags: { process: "agent-server" } },
 20→  });
 21→}
 22→
 23→import * as net from "net";
 24→import * as fs from "fs";
 25→import * as path from "path";
 26→import * as os from "os";
 27→import * as util from "util";
 28→import { exec } from "child_process";
 29→import { StringDecoder } from "string_decoder";
 30→import { createServer as createHttpServer } from "http";
 31→import { WebSocketServer, WebSocket } from "ws";
 32→
 33→import { getErrorMessage } from "@shared/lib/errors";
 34→import { RpcConnection, wsTransport } from "./rpc-connection";
 35→import { EventBroadcaster } from "./event-broadcaster";
 36→import { classifyError } from "./agents/lifecycle";
 37→import { registerAgent, getAgent, initializeAllAgents } from "./agents/registry";
 38→import { ClaudeAgentHandler } from "./agents/claude/claude-handler";
 39→import { CodexAgentHandler } from "./agents/codex/codex-handler";
 40→import {
 41→  handleHttpRequest,
 42→  isShuttingDown,
 43→  setShuttingDown,
 44→  setAgentsInitialized,
 45→  trackSession,
 46→  untrackSession,
 47→  waitForDrain,
 48→  cancelRemainingSessions,
 49→} from "./health";
 50→
 51→// ============================================================================
 52→// Logging
 53→// ============================================================================
 54→
 55→export const logFilePath = `/tmp/deus-${process.pid}.log`;
 56→const originalLog = console.log;
 57→
 58→const LOG_LEVEL = (process.env.LOG_LEVEL || "info") as "debug" | "info" | "error";
 59→const LOG_LEVELS = { debug: 0, info: 1, error: 2 };
 60→
 61→function shouldLog(level: "debug" | "info" | "error"): boolean {
 62→  return LOG_LEVELS[level] >= LOG_LEVELS[LOG_LEVEL];
 63→}
 64→
 65→function formatLogArgs(args: any[]): string {
 66→  return args
 67→    .map((arg) => {
 68→      if (typeof arg === "string") return arg;
 69→      if (arg instanceof Error) return `${arg.message}\n${arg.stack || ""}`;
 70→      return util.inspect(arg, { depth: 4, breakLength: Infinity });
 71→    })
 72→    .join(" ");
 73→}
 74→
 75→// Buffered log writer -- avoids synchronous appendFileSync on every log call
 76→let logBuffer = "";
 77→let flushTimer: NodeJS.Timeout | null = null;
 78→
 79→function flushLogs(): void {
 80→  if (logBuffer) {
 81→    fs.appendFileSync(logFilePath, logBuffer);
 82→    logBuffer = "";
 83→  }
 84→  flushTimer = null;
 85→}
 86→
 87→function writeLog(line: string): void {
 88→  logBuffer += line;
 89→  if (!flushTimer) {
 90→    flushTimer = setTimeout(flushLogs, 100);
 91→  }
 92→  if (logBuffer.length > 8192) {
 93→    flushLogs();
 94→  }
 95→}
 96→
 97→// Ensure logs are flushed on shutdown
 98→process.on("exit", flushLogs);
 99→
100→console.log = (...args: any[]) => {
101→  if (!shouldLog("info")) return;
102→  const timestamp = new Date().toISOString();
103→  writeLog(`[${timestamp}] ${formatLogArgs(args)}\n`);
104→};
105→
106→console.error = (...args: any[]) => {
107→  const timestamp = new Date().toISOString();
108→  writeLog(`[${timestamp}] ERROR: ${formatLogArgs(args)}\n`);
109→};
110→
111→console.debug = (...args: any[]) => {
112→  if (!shouldLog("debug")) return;
113→  const timestamp = new Date().toISOString();
114→  writeLog(`[${timestamp}] DEBUG: ${formatLogArgs(args)}\n`);
115→};
116→
117→// ============================================================================
118→// CLI flag parsing
119→// ============================================================================
120→
121→type TransportMode = "ws" | "unix";
122→
123→function parseTransportMode(): TransportMode {
124→  const listenIdx = process.argv.indexOf("--listen");
125→  if (listenIdx === -1) return "ws"; // Default: WebSocket
126→  const value = process.argv[listenIdx + 1] || "";
127→  if (value.startsWith("unix://")) return "unix";
128→  if (value.startsWith("ws://") || value === "") return "ws";
129→  // Unknown scheme — default to ws
130→  console.error(`[CLI] Unknown --listen scheme "${value}", defaulting to ws://`);
131→  return "ws";
132→}
133→
134→// ============================================================================
135→// AgentServer
136→// ============================================================================
137→
138→class AgentServer {
139→  private transportMode: TransportMode;
140→  private initializedAgents = new Set<string>();
141→
142→  // Unix socket transport
143→  private socketPath: string;
144→  private unixServer: net.Server | null = null;
145→
146→  // WebSocket transport
147→  private httpServer: ReturnType<typeof createHttpServer> | null = null;
148→  private wss: WebSocketServer | null = null;
149→
150→  constructor(mode: TransportMode) {
151→    this.transportMode = mode;
152→    this.socketPath = path.join(os.tmpdir(), `deus-agent-server-${process.pid}.sock`);
153→
154→    console.log(`AgentServer: Initializing (transport=${mode})...`);
155→
156→    // Graceful shutdown handlers — drain in-flight turns before exiting
157→    const gracefulShutdown = async (signal: string) => {
158→      console.log(`\n[SIGNAL] Received ${signal}, shutting down gracefully...`);
159→
160→      // 1. Stop accepting new turn/start requests
161→      setShuttingDown(true);
162→
163→      // 2. Stop accepting new WS connections (close the HTTP listener)
164→      if (this.httpServer) {
165→        this.httpServer.close();
166→        console.log("[SHUTDOWN] HTTP server closed to new connections");
167→      }
168→      if (this.unixServer) {
169→        this.unixServer.close();
170→        console.log("[SHUTDOWN] Unix server closed to new connections");
171→      }
172→
173→      // 3. Wait for in-flight turns to drain (default 30s timeout)
174→      console.log("[SHUTDOWN] Waiting for in-flight turns to drain...");
175→      const drained = await waitForDrain();
176→      if (drained) {
177→        console.log("[SHUTDOWN] All turns drained successfully");
178→      } else {
179→        console.log("[SHUTDOWN] Drain timeout reached, cancelling remaining sessions");
180→        await cancelRemainingSessions();
181→      }
182→
183→      // 4. Full cleanup (kill child processes, close WS clients)
184→      try {
185→        await this.cleanup();
186→        console.log("[SIGNAL] Cleanup complete, exiting process");
187→      } catch (error) {
188→        console.error("[SIGNAL] Cleanup failed:", error);
189→      } finally {
190→        process.exit(0);
191→      }
192→    };
193→    process.on("SIGINT", () => gracefulShutdown("SIGINT"));
194→    process.on("SIGTERM", () => gracefulShutdown("SIGTERM"));
195→  }
196→
197→  /**
198→   * Wires up all JSON-RPC methods and notifications on a new connection.
199→   * Transport-agnostic — works with both Unix socket and WebSocket tunnels.
200→   */
201→  private setupJsonRpc(rpcTunnel: RpcConnection): void {
202→    EventBroadcaster.attachTunnel(rpcTunnel);
203→
204→    // --- Initialize handshake (backend agent-client sends this) ---
205→    rpcTunnel.addMethod("initialize", () => {
206→      const agents = [];
207→      for (const [agentType, handler] of [
208→        ["claude", getAgent("claude")],
209→        ["codex", getAgent("codex")],
210→      ] as const) {
211→        if (handler && this.initializedAgents.has(agentType)) {
212→          agents.push({
213→            type: agentType,
214→            capabilities: handler.capabilities,
215→            initialized: true,
216→          });
217→        }
218→      }
219→      return { version: "1.0", agents };
220→    });
221→
222→    // --- Initialized notification (backend confirms handshake) ---
223→    rpcTunnel.addMethod("initialized", () => {
224→      console.log("[RPC] Backend handshake complete (initialized)");
225→      return undefined;
226→    });
227→
228→    // --- turn/start (new wire protocol method, maps to query dispatch) ---
229→    rpcTunnel.addMethod("turn/start", async (params: any) => {
230→      const sessionId = params?.sessionId;
231→      const agentType = params?.agentType || "claude";
232→      const prompt = params?.prompt;
233→      const options = params?.options || {};
234→
235→      // Reject new turns during shutdown
236→      if (isShuttingDown()) {
237→        return { accepted: false, reason: "shutting down" };
238→      }
239→
240→      if (!sessionId || !prompt) {
241→        return { accepted: false, reason: "turn/start requires sessionId and prompt" };
242→      }
243→
244→      const agent = getAgent(agentType);
245→      if (!agent) {
246→        return { accepted: false, reason: `No agent registered for type: ${agentType}` };
247→      }
248→
249→      // Track this session for graceful shutdown draining
250→      trackSession(sessionId, agentType);
251→
252→      agent
253→        .query(sessionId, prompt, options)
254→        .catch((err) => {
255→          console.error(`[turn/start] Unhandled error in ${agentType} query:`, err);
256→          const classified = classifyError(err);
257→          EventBroadcaster.sendError({
258→            id: sessionId,
259→            type: "error",
260→            error: classified.message,
261→            agentType,
262→            category: classified.category,
263→          });
264→          EventBroadcaster.emitSessionError(
265→            sessionId,
266→            agentType,
267→            classified.message,
268→            classified.category
269→          );
270→        })
271→        .finally(() => {
272→          // Untrack when the turn completes (success, error, or cancel)
273→          untrackSession(sessionId);
274→        });
275→
276→      EventBroadcaster.emitSessionStarted(sessionId, agentType);
277→
278→      console.log(`[TIMING][turn/start] DISPATCHED session=${sessionId}`);
279→      return { accepted: true };
280→    });
281→
282→    // --- turn/respond (tool relay response from backend) ---
283→    // Currently a stub: the agent-server tools use direct JSON-RPC requests
284→    // (EventBroadcaster.requestBrowserXxx) rather than the canonical
285→    // tool.request notification path. When tools migrate to the canonical
286→    // path, this handler will resolve pending promises by requestId.
287→    rpcTunnel.addMethod("turn/respond", (params: any) => {
288→      const { requestId } = params ?? {};
289→      console.log(`[AgentServer] turn/respond received (requestId=${requestId})`);
290→    });
291→
292→    // --- turn/cancel (new wire protocol method, maps to cancel dispatch) ---
293→    rpcTunnel.addMethod("turn/cancel", async (params: any) => {
294→      const sessionId = params?.sessionId;
295→      if (!sessionId) return;
296→
297→      // Try all registered agents — the backend may not send agentType for cancel
298→      for (const agentType of ["claude", "codex"] as const) {
299→        const agent = getAgent(agentType);
300→        if (agent) void agent.cancel(sessionId);
301→      }
302→    });
303→
304→    // --- session/reset (new wire protocol method) ---
305→    rpcTunnel.addMethod("session/reset", (params: any) => {
306→      const sessionId = params?.sessionId;
307→      if (!sessionId) return;
308→
309→      for (const agentType of ["claude", "codex"] as const) {
310→        const agent = getAgent(agentType);
311→        if (agent) agent.reset(sessionId);
312→      }
313→    });
314→
315→    // --- session/stop (stop a running session) ---
316→    rpcTunnel.addMethod("session/stop", async (params: any) => {
317→      const sessionId = params?.sessionId;
318→      if (!sessionId) return;
319→
320→      for (const agentType of ["claude", "codex"] as const) {
321→        const agent = getAgent(agentType);
322→        if (agent) void agent.cancel(sessionId);
323→      }
324→    });
325→
326→    // --- provider/auth (check agent authentication) ---
327→    rpcTunnel.addMethod("provider/auth", async (params: any) => {
328→      const agentType = params?.agentType || "claude";
329→      const agent = getAgent(agentType);
330→      if (!agent?.auth) throw new Error(`Agent "${agentType}" does not support auth`);
331→      return agent.auth({ cwd: params?.cwd });
332→    });
333→
334→    // --- provider/initWorkspace (slash commands, MCP servers) ---
335→    rpcTunnel.addMethod("provider/initWorkspace", async (params: any) => {
336→      const agentType = params?.agentType || "claude";
337→      const agent = getAgent(agentType);
338→      if (!agent?.initWorkspace)
339→        throw new Error(`Agent "${agentType}" does not support workspace init`);
340→      return agent.initWorkspace({
341→        cwd: params?.cwd,
342→        ghToken: params?.ghToken,
343→        providerEnvVars: params?.providerEnvVars,
344→      });
345→    });
346→
347→    // --- provider/contextUsage (token usage stats) ---
348→    rpcTunnel.addMethod("provider/contextUsage", async (params: any) => {
349→      const agentType = params?.agentType || "claude";
350→      const agent = getAgent(agentType);
351→      if (!agent?.getContextUsage)
352→        throw new Error(`Agent "${agentType}" does not support context usage`);
353→      return agent.getContextUsage({
354→        options: {
355→          cwd: params?.cwd ?? "",
356→          agentSessionId: params?.agentSessionId ?? "",
357→        },
358→      });
359→    });
360→
361→    // --- provider/updateMode (runtime permission mode change) ---
362→    rpcTunnel.addMethod("provider/updateMode", (params: any) => {
363→      const agentType = params?.agentType || "claude";
364→      const agent = getAgent(agentType);
365→      if (agent?.updatePermissionMode) {
366→        void agent.updatePermissionMode(params?.sessionId, params?.permissionMode);
367→      }
368→    });
369→
370→    // --- agent/list (introspection: list available agents) ---
371→    rpcTunnel.addMethod("agent/list", () => {
372→      const agents = [];
373→      for (const [agentType, handler] of [
374→        ["claude", getAgent("claude")],
375→        ["codex", getAgent("codex")],
376→      ] as const) {
377→        if (handler && this.initializedAgents.has(agentType)) {
378→          agents.push({ type: agentType, capabilities: handler.capabilities });
379→        }
380→      }
381→      return { agents };
382→    });
383→  }
384→
385→  // ==========================================================================
386→  // Unix socket transport
387→  // ==========================================================================
388→
389→  /**
390→   * Handles a new TCP/Unix socket connection.
391→   * Sets up line-based JSON-RPC message framing.
392→   */
393→  private handleUnixConnection(socket: net.Socket): void {
394→    console.log("Client connected (unix)");
395→    const rpcTunnel = new RpcConnection(socket);
396→    this.setupJsonRpc(rpcTunnel);
397→
398→    let buffer = "";
399→    const decoder = new StringDecoder("utf8");
400→
401→    socket.on("data", (data) => {
402→      buffer += decoder.write(data);
403→      console.debug("Received data with length", data.length);
404→
405→      const lines = buffer.split("\n");
406→      buffer = lines.pop() || "";
407→
408→      for (const line of lines) {
409→        if (line.trim()) {
410→          rpcTunnel.handleLine(line);
411→        }
412→      }
413→    });
414→
415→    socket.on("error", (error: any) => {
416→      console.error("Socket error:", error);
417→    });
418→
419→    socket.on("close", (hadError) => {
420→      console.log(`Client disconnected (unix), hadError: ${hadError}`);
421→      rpcTunnel.stop();
422→      EventBroadcaster.detachTunnel(rpcTunnel);
423→    });
424→  }
425→
426→  // ==========================================================================
427→  // WebSocket transport
428→  // ==========================================================================
429→
430→  /**
431→   * Handles a new WebSocket connection.
432→   * Each WS text frame is a complete JSON-RPC message (no line splitting needed).
433→   */
434→  private handleWsConnection(ws: WebSocket): void {
435→    console.log("Client connected (ws)");
436→    const transport = wsTransport(ws);
437→    const rpcTunnel = new RpcConnection(transport);
438→    this.setupJsonRpc(rpcTunnel);
439→
440→    ws.on("message", (data: Buffer | string) => {
441→      const message = typeof data === "string" ? data : data.toString("utf8");
442→      console.debug("Received WS message with length", message.length);
443→      rpcTunnel.handleMessage(message);
444→    });
445→
446→    ws.on("error", (error: Error) => {
447→      console.error("WebSocket error:", error);
448→    });
449→
450→    ws.on("close", (code: number, reason: Buffer) => {
451→      console.log(`Client disconnected (ws), code=${code} reason=${reason.toString()}`);
452→      rpcTunnel.stop();
453→      EventBroadcaster.detachTunnel(rpcTunnel);
454→    });
455→  }
456→
457→  // ==========================================================================
458→  // Lifecycle
459→  // ==========================================================================
460→
461→  /**
462→   * Kills any remaining Claude child processes spawned by this agent-server.
463→   */
464→  private async killRemainingChildProcesses(): Promise<void> {
465→    return new Promise((resolve) => {
466→      const command = `/usr/bin/pgrep -P ${process.pid}`;
467→      exec(command, (error, stdout) => {
468→        if (error) {
469→          console.log("[CLEANUP] No child processes found");
470→          resolve();
471→          return;
472→        }
473→        const childPids = stdout
474→          .trim()
475→          .split("\n")
476→          .filter((pid) => pid);
477→        if (childPids.length === 0) {
478→          console.log("[CLEANUP] No child processes to kill");
479→          resolve();
480→          return;
481→        }
482→        console.log(`[CLEANUP] Found ${childPids.length} child processes: ${childPids.join(", ")}`);
483→        childPids.forEach((pid) => {
484→          try {
485→            process.kill(Number(pid), "SIGTERM");
486→            console.log(`[CLEANUP] Sent SIGTERM to child PID ${pid}`);
487→          } catch (e) {
488→            const errorMsg = getErrorMessage(e);
489→            console.log(`[CLEANUP] Failed to kill child PID ${pid}: ${errorMsg}`);
490→          }
491→        });
492→        resolve();
493→      });
494→    });
495→  }
496→
497→  private async cleanup(): Promise<void> {
498→    await this.killRemainingChildProcesses();
499→
500→    // Clean up Unix socket
501→    if (fs.existsSync(this.socketPath)) {
502→      fs.unlinkSync(this.socketPath);
503→      console.log("[CLEANUP] Removed socket file");
504→    }
505→    if (this.unixServer) {
506→      this.unixServer.close();
507→    }
508→
509→    // Clean up WebSocket server
510→    if (this.wss) {
511→      // Close all connected clients
512→      for (const client of this.wss.clients) {
513→        client.close(1001, "Server shutting down");
514→      }
515→      this.wss.close();
516→    }
517→    if (this.httpServer) {
518→      this.httpServer.close();
519→    }
520→  }
521→
522→  /**
523→   * Starts the agent-server:
524→   * 1. Clean up stale resources
525→   * 2. Initialize agent handlers
526→   * 3. Listen on the selected transport
527→   * 4. Print connection info to stdout (consumed by the Electron main process)
528→   */
529→  async start(): Promise<void> {
530→    await this.cleanup();
531→
532→    // Register all agent handlers
533→    registerAgent(new ClaudeAgentHandler());
534→    registerAgent(new CodexAgentHandler());
535→
536→    // Initialize all registered agents
537→    console.log("Initializing agent handlers...");
538→    this.initializedAgents.clear();
539→    const initResults = initializeAllAgents();
540→    for (const [agentType, result] of initResults) {
541→      if (!result.success) {
542→        console.error(`${agentType} initialization failed:`, result.error);
543→      } else {
544→        console.log(`${agentType} handler initialized successfully`);
545→        this.initializedAgents.add(agentType);
546→      }
547→    }
548→
549→    // Mark agents as initialized for the /readyz endpoint only if at least one succeeded
550→    setAgentsInitialized(this.initializedAgents.size > 0);
551→
552→    if (this.transportMode === "ws") {
553→      return this.startWebSocket();
554→    } else {
555→      return this.startUnixSocket();
556→    }
557→  }
558→
559→  private startWebSocket(): Promise<void> {
560→    return new Promise((resolve, reject) => {
561→      // Create an HTTP server for health endpoints + WS upgrade.
562→      // Binding to 127.0.0.1 — agent-server only accepts local connections.
563→      this.httpServer = createHttpServer((req, res) => {
564→        handleHttpRequest(req, res, this.wss);
565→      });
566→
567→      this.wss = new WebSocketServer({ server: this.httpServer });
568→
569→      this.wss.on("connection", (ws) => {
570→        console.log("Server: New WebSocket connection accepted");
571→        this.handleWsConnection(ws);
572→      });
573→
574→      this.wss.on("error", (error: Error) => {
575→        console.error("WebSocketServer error:", error);
576→      });
577→
578→      // Port 0 = OS-assigned dynamic port
579→      this.httpServer.listen(0, "127.0.0.1", () => {
580→        const addr = this.httpServer!.address();
581→        const port = typeof addr === "object" && addr ? addr.port : 0;
582→
583→        console.log(`Agent-server listening on ws://127.0.0.1:${port}`);
584→        console.log(`Agent-server PID: ${process.pid}`);
585→
586→        // Machine-readable output for the Electron main process.
587→        // LISTEN_URL is the new canonical output; SOCKET_PATH kept for transition.
588→        originalLog(`LISTEN_URL=ws://127.0.0.1:${port}`);
589→        resolve();
590→      });
591→
592→      this.httpServer.on("error", (error: Error) => {
593→        console.error("HTTP server error:", error);
594→        reject(error);
595→      });
596→    });
597→  }
598→
599→  private startUnixSocket(): Promise<void> {
600→    return new Promise((resolve, reject) => {
601→      this.unixServer = net.createServer((socket) => {
602→        console.log("Server: New connection accepted");
603→        this.handleUnixConnection(socket);
604→      });
605→
606→      this.unixServer.listen(this.socketPath, () => {
607→        console.log(`Agent-server listening on ${this.socketPath}`);
608→        console.log(`Agent-server PID: ${process.pid}`);
609→
610→        // Print the socket path to stdout so the Deus app can connect
611→        originalLog(`SOCKET_PATH=${this.socketPath}`);
612→        resolve();
613→      });
614→
615→      this.unixServer.on("error", (error: any) => {
616→        console.error("Server error:", error);
617→        reject(error);
618→      });
619→    });
620→  }
621→}
622→
623→// ============================================================================
624→// Global error handlers
625→// ============================================================================
626→
627→process.on("uncaughtException", (error: any) => {
628→  console.error("Uncaught Exception:", error.message);
629→  if (error.stack) console.error("Stack:", error.stack);
630→  Sentry.captureException(error);
631→  Sentry.close(2000).finally(() => process.exit(1));
632→});
633→
634→process.on("unhandledRejection", (reason, _promise) => {
635→  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
636→  // rejection reasons automatically. We only log here for local visibility.
637→  if (reason instanceof Error) {
638→    console.error("Unhandled Rejection:", reason.message);
639→    if (reason.stack) console.error("Stack:", reason.stack);
640→  }
641→  console.error("Unhandled Rejection Reason:", JSON.stringify(reason, null, 2));
642→});
643→
644→// ============================================================================
645→// Bootstrap
646→// ============================================================================
647→
648→const mode = parseTransportMode();
649→const server = new AgentServer(mode);
650→server.start().catch((error) => {
651→  console.error("Startup failed:", error);
652→  process.exit(1);
653→});
