101→    // Duck-type: if it has send() and isClosed(), treat as RpcTransport.
102→    // Otherwise, wrap as a net.Socket via socketTransport().
103→    this.transport = isRpcTransport(transportOrSocket)
104→      ? transportOrSocket
105→      : socketTransport(transportOrSocket as Socket);
106→
107→    const server = new JSONRPCServer({
108→      errorListener: (message, data) => {
109→        console.error("[RpcConnection] Server error:", message, data);
110→      },
111→    });
112→
113→    const client = new JSONRPCClient((payload) => {
114→      if (this.transport.isClosed()) {
115→        return Promise.reject(new Error("Transport is closed"));
116→      }
117→      try {
118→        this.transport.send(JSON.stringify(payload));
119→        return Promise.resolve();
120→      } catch (error) {
121→        const err = error instanceof Error ? error : new Error(String(error));
122→        return Promise.reject(err);
123→      }
124→    });
125→
126→    this.peer = new JSONRPCServerAndClient(server, client, {
127→      errorListener: (message, data) => {
128→        console.error("[RpcConnection] Client error:", message, data);
129→      },
130→    });
131→  }
