133→  /** Register a method handler that the remote side can call */
134→  addMethod(name: string, method: (params: unknown) => Promise<unknown>): void {
135→    this.peer.addMethod(name, (params) => method(params));
136→  }
137→
138→  /** Send a one-way notification to the remote side */
139→  notify(method: string, params: unknown): void {
140→    this.peer.notify(method, params, undefined);
141→  }
142→
143→  /** Send a request to the remote side and wait for a response */
144→  request(method: string, params: unknown): Promise<unknown> {
145→    return Promise.resolve(this.peer.request(method, params, undefined));
146→  }
147→
148→  /**
149→   * Process a single line/message received from the transport.
150→   * Works for both NDJSON lines (net.Socket) and WS text frames.
151→   * Returns true if the line was a valid JSON-RPC payload.
152→   */
153→  handleLine(line: string): boolean {
154→    const t0 = Date.now();
155→    const payload = safeJsonParse(line);
156→    if (payload === undefined) {
157→      console.error("[RpcConnection] Failed to parse JSON:", line);
158→      return false;
159→    }
160→    if (!isJsonRpcPayload(payload)) {
161→      console.error("[RpcConnection] Received non-JSON-RPC payload:", payload);
162→      return false;
163→    }
164→
165→    const method = (payload as any)?.method;
166→    if (method) {
167→      console.log(
168→        `[TIMING][RpcConnection] handleLine method=${method} parseTime=${Date.now() - t0}ms lineLen=${line.length}`
169→      );
170→    }
171→
172→    void this.peer.receiveAndSend(payload, undefined, undefined).catch((e) => {
173→      console.error("[RpcConnection] Failed to handle message:", e);
174→    });
175→    return true;
176→  }
177→
178→  /** Alias for handleLine — clearer name when used with WebSocket messages. */
179→  handleMessage(message: string): boolean {
180→    return this.handleLine(message);
181→  }
182→
183→  /** Reject all pending outbound requests and tear down the connection */
184→  stop(): void {
185→    this.peer.rejectAllPendingRequests("RPC connection stopped");
186→  }
187→}
188→
