190→// Type guard
191→// ============================================================================
192→
193→/**
194→ * Duck-type check: RpcTransport has `send` (function) and `isClosed` (function).
195→ * Anything that doesn't match is treated as a net.Socket (which has `write`).
196→ */
197→function isRpcTransport(obj: unknown): obj is RpcTransport {
198→  return (
199→    typeof obj === "object" &&
200→    obj !== null &&
201→    typeof (obj as any).send === "function" &&
202→    typeof (obj as any).isClosed === "function"
203→  );
