  1→import { describe, it, expect, beforeAll, afterAll } from "vitest";
  2→import { spawn, ChildProcess, execSync } from "child_process";
  3→import * as net from "net";
  4→import * as fs from "fs";
  5→import * as path from "path";
  6→import * as os from "os";
  7→import { StringDecoder } from "string_decoder";
  8→
  9→/**
 10→ * End-to-end tests: Spawn a real agent-server process, connect via
 11→ * Unix domain socket, send JSON-RPC messages, verify responses.
 12→ *
 13→ * Three test suites:
 14→ * 1. Protocol compliance — tests JSON-RPC protocol handling (always runs)
 15→ * 2. Real Claude integration — tests actual Claude SDK calls (skipped if CLI unavailable)
 16→ * 3. Real Codex integration — tests actual Codex SDK calls (skipped if no OPENAI_API_KEY)
 17→ *
 18→ * NOTE: These tests require:
 19→ * 1. The agent-server bundle to be built: `bunx tsx agent-server/build.ts`
 20→ * 2. Claude CLI to be installed (for Claude integration tests)
 21→ * 3. OPENAI_API_KEY env var (for Codex integration tests — CLI binary comes from npm)
 22→ */
 23→
 24→const AGENT_SERVER_DIR = path.resolve(__dirname, "..");
 25→const BUNDLE_PATH = path.resolve(AGENT_SERVER_DIR, "dist", "index.bundled.cjs");
 26→
 27→// The workspace root — a real git repo for integration tests
 28→const WORKSPACE_ROOT = path.resolve(AGENT_SERVER_DIR, "..");
 29→
 30→// Check if the bundle exists before running E2E tests
 31→const bundleExists = fs.existsSync(BUNDLE_PATH);
 32→
 33→// Check if Claude CLI is available on this machine.
 34→// We only check if the executable exists (not run it) because running
 35→// `claude -v` can crash in vitest's Node.js context due to module
 36→// compatibility issues with the Claude Code SDK.
 37→let claudeCliAvailable = false;
 38→try {
 39→  const shell = process.env.SHELL || "/bin/zsh";
 40→  const claudePath = execSync(`${shell} -l -c "command -v claude"`, {
 41→    encoding: "utf-8",
 42→    timeout: 5000,
 43→  }).trim();
 44→  if (claudePath && fs.existsSync(claudePath)) {
 45→    claudeCliAvailable = true;
 46→  }
 47→} catch {
 48→  // Claude CLI not installed — integration tests will be skipped
 49→}
 50→
 51→// Check if Codex can run — the binary comes bundled with @openai/codex (npm dep),
 52→// so we only need an API key to actually hit the OpenAI API.
 53→const hasOpenAIKey = !!(process.env.OPENAI_API_KEY || process.env.CODEX_API_KEY);
 54→
 55→// In CI, integration tests MUST run — fail if prerequisites are missing, don't skip.
 56→// Locally, gracefully skip when keys/CLI are unavailable.
 57→const isCI = !!process.env.CI;
 58→
 59→// ============================================================================
 60→// CI prerequisite guard — fail fast with clear messages
 61→// ============================================================================
 62→
 63→if (isCI) {
 64→  describe("CI: Required E2E prerequisites", () => {
 65→    it("agent-server bundle exists", () => {
 66→      expect(bundleExists, "Run 'bun run build:agent-server' before E2E tests").toBe(true);
 67→    });
 68→
 69→    it("OPENAI_API_KEY is set for Codex tests", () => {
 70→      expect(
 71→        hasOpenAIKey,
 72→        "Add OPENAI_API_KEY as a GitHub Actions secret (Settings → Secrets → Actions)"
 73→      ).toBe(true);
 74→    });
 75→  });
 76→}
 77→
 78→// ============================================================================
 79→// Helpers
 80→// ============================================================================
 81→
 82→/** Wait for a message matching a predicate from the socket */
 83→function waitForMessage(
 84→  socket: net.Socket,
 85→  predicate: (msg: any) => boolean,
 86→  timeoutMs = 10000
 87→): Promise<any> {
 88→  return new Promise((resolve, reject) => {
 89→    let buffer = "";
 90→    const decoder = new StringDecoder("utf8");
 91→    const timer = setTimeout(() => {
 92→      socket.removeListener("data", onData);
 93→      reject(new Error(`waitForMessage timed out after ${timeoutMs}ms`));
 94→    }, timeoutMs);
 95→
 96→    function onData(data: Buffer) {
 97→      buffer += decoder.write(data);
 98→      const lines = buffer.split("\n");
 99→      buffer = lines.pop() || "";
100→
101→      for (const line of lines) {
102→        if (!line.trim()) continue;
103→        try {
104→          const msg = JSON.parse(line);
105→          if (predicate(msg)) {
106→            clearTimeout(timer);
107→            socket.removeListener("data", onData);
108→            resolve(msg);
109→            return;
110→          }
111→        } catch {
112→          // Ignore parse errors
113→        }
114→      }
115→    }
116→
117→    socket.on("data", onData);
118→  });
119→}
120→
121→/** Collect all messages from a socket into an array (non-blocking) */
122→function collectMessages(socket: net.Socket): any[] {
123→  const messages: any[] = [];
124→  let buffer = "";
125→  const decoder = new StringDecoder("utf8");
126→
127→  socket.on("data", (data) => {
128→    buffer += decoder.write(data);
129→    const lines = buffer.split("\n");
130→    buffer = lines.pop() || "";
131→    for (const line of lines) {
132→      if (!line.trim()) continue;
133→      try {
134→        messages.push(JSON.parse(line));
135→      } catch {
136→        // Ignore parse errors
137→      }
138→    }
139→  });
140→
141→  return messages;
142→}
143→
144→/** Send a JSON-RPC notification (fire-and-forget) */
145→function sendNotification(socket: net.Socket, method: string, params: any): void {
146→  const msg = JSON.stringify({ jsonrpc: "2.0", method, params });
147→  socket.write(msg + "\n");
148→}
149→
150→/** Send a JSON-RPC request and return its ID */
151→let rpcIdCounter = 1;
152→function sendRequest(socket: net.Socket, method: string, params: any): number {
153→  const id = rpcIdCounter++;
154→  const msg = JSON.stringify({ jsonrpc: "2.0", id, method, params });
155→  socket.write(msg + "\n");
156→  return id;
157→}
158→
159→/** Wait until a file exists and has content, then return its contents. */
160→async function readFileWithRetry(filePath: string, timeoutMs = 5000): Promise<string> {
161→  const startedAt = Date.now();
162→
163→  while (Date.now() - startedAt < timeoutMs) {
164→    if (fs.existsSync(filePath)) {
165→      try {
166→        const content = fs.readFileSync(filePath, "utf-8");
167→        if (content.length > 0) return content;
168→      } catch {
169→        // Keep retrying while file is being written/flushed
170→      }
171→    }
172→    await new Promise((resolve) => setTimeout(resolve, 100));
173→  }
174→
175→  throw new Error(`Timed out waiting for log file: ${filePath}`);
176→}
177→
178→/** Spawn an agent-server process and connect a client socket */
179→async function spawnAgentServer(): Promise<{
180→  process: ChildProcess;
181→  socketPath: string;
182→  client: net.Socket;
183→  logPath: string;
184→}> {
185→  // The agent-server is stateless — no DATABASE_PATH needed.
186→  const proc = spawn("node", [BUNDLE_PATH, "--listen", "unix://"], {
187→    env: {
188→      ...process.env,
189→      LOG_LEVEL: "debug",
190→    },
191→    stdio: ["pipe", "pipe", "pipe"],
192→  });
193→
194→  let stderrOutput = "";
195→  proc.stderr?.on("data", (data) => {
196→    stderrOutput += data.toString();
197→  });
198→
199→  // Wait for SOCKET_PATH= from stdout
200→  const socketPath = await new Promise<string>((resolve, reject) => {
201→    let stdoutBuffer = "";
202→    const timeout = setTimeout(() => {
203→      reject(
204→        new Error(`Agent-server did not print SOCKET_PATH within 15s. stderr: ${stderrOutput}`)
205→      );
206→    }, 15_000);
207→
208→    proc.stdout?.on("data", (data) => {
209→      stdoutBuffer += data.toString();
210→      const match = stdoutBuffer.match(/SOCKET_PATH=(.+)/);
211→      if (match) {
212→        clearTimeout(timeout);
213→        resolve(match[1].trim());
214→      }
215→    });
216→
217→    proc.on("exit", (code) => {
218→      clearTimeout(timeout);
219→      reject(new Error(`Agent-server exited with code ${code}. stderr: ${stderrOutput}`));
220→    });
221→  });
222→
223→  // Connect to the agent-server's Unix domain socket
224→  const client = await new Promise<net.Socket>((resolve, reject) => {
225→    const timeout = setTimeout(() => reject(new Error("Client connection timed out")), 5000);
226→    const sock = net.connect(socketPath, () => {
227→      clearTimeout(timeout);
228→      resolve(sock);
229→    });
230→    sock.on("error", (err) => {
231→      clearTimeout(timeout);
232→      reject(err);
233→    });
234→  });
235→
236→  const logPath = `/tmp/deus-${proc.pid}.log`;
237→
238→  return { process: proc, socketPath, client, logPath };
239→}
240→
241→/** Kill an agent-server process and clean up */
242→async function killAgentServer(srv: {
243→  process: ChildProcess;
244→  socketPath: string;
245→  client: net.Socket;
246→}): Promise<void> {
247→  if (srv.client) {
248→    srv.client.destroy();
249→  }
250→  if (srv.process) {
251→    srv.process.kill("SIGTERM");
252→    await new Promise<void>((resolve) => {
253→      srv.process.on("exit", () => resolve());
254→      setTimeout(resolve, 3000);
255→    });
256→  }
257→  if (srv.socketPath && fs.existsSync(srv.socketPath)) {
258→    try {
259→      fs.unlinkSync(srv.socketPath);
260→    } catch {
261→      // ignore
262→    }
263→  }
264→}
