388→  it("discovers Claude CLI during initialization", async () => {
389→    // The agent-server log records whether initialization succeeded
390→    const log = await readFileWithRetry(logPath, 7000);
391→    expect(log).toContain("Claude executable initialized with version:");
392→    expect(log).toContain("handler initialized successfully");
393→    // Must NOT contain the initialization failure message
394→    expect(log).not.toContain("initialization failed");
