  // Workspace initialization (real Claude SDK call)
  // ------------------------------------------------------------------

  it("returns slash commands and MCP servers via workspaceInit", async () => {
    const id = sendRequest(client, "provider/initWorkspace", {
      agentType: "claude",
      id: "test-workspace-init",
      cwd: WORKSPACE_ROOT,
    });

