function flushLogs(): void {
  if (logBuffer) {
    fs.appendFileSync(logFilePath, logBuffer);
    logBuffer = "";
  }
  flushTimer = null;
}

function writeLog(line: string): void {
  logBuffer += line;
  if (!flushTimer) {
    flushTimer = setTimeout(flushLogs, 100);
  }
  if (logBuffer.length > 8192) {
    flushLogs();
