178→/** Spawn an agent-server process and connect a client socket */
179→async function spawnAgentServer(): Promise<{
180→  process: ChildProcess;
181→  socketPath: string;
182→  client: net.Socket;
183→  logPath: string;
184→}> {
185→  // The agent-server is stateless — no DATABASE_PATH needed.
