192→  });
193→
194→  let stderrOutput = "";
195→  proc.stderr?.on("data", (data) => {
196→    stderrOutput += data.toString();
197→  });
198→
199→  // Wait for SOCKET_PATH= from stdout
200→  const socketPath = await new Promise<string>((resolve, reject) => {
201→    let stdoutBuffer = "";
202→    const timeout = setTimeout(() => {
