 56→
 57→function formatLogArgs(args: any[]): string {
 58→  return args
 59→    .map((arg) => {
 60→      if (typeof arg === "string") return arg;
 61→      if (arg instanceof Error) return `${arg.message}\n${arg.stack || ""}`;
 62→      return util.inspect(arg, { depth: 4, breakLength: Infinity });
 63→    })
 64→    .join(" ");
