 67→// Buffered log writer -- avoids synchronous appendFileSync on every log call
 68→let logBuffer = "";
 69→let flushTimer: NodeJS.Timeout | null = null;
 70→
 71→function flushLogs(): void {
 72→  if (logBuffer) {
 73→    fs.appendFileSync(logFilePath, logBuffer);
 74→    logBuffer = "";
 75→  }
 76→  flushTimer = null;
 77→}
 78→
 79→function writeLog(line: string): void {
 80→  logBuffer += line;
 81→  if (!flushTimer) {
 82→    flushTimer = setTimeout(flushLogs, 100);
 83→  }
 84→  if (logBuffer.length > 8192) {
 85→    flushLogs();
 86→  }
 87→}
