158→  /**
159→   * Wires up all JSON-RPC methods and notifications on a new connection.
160→   * Transport-agnostic — works with both Unix socket and WebSocket tunnels.
161→   */
162→  private setupJsonRpc(rpcTunnel: RpcConnection): void {
163→    EventBroadcaster.attachTunnel(rpcTunnel);
164→
165→    // --- Initialize handshake (backend agent-client sends this) ---
166→    rpcTunnel.addMethod("initialize", () => {
167→      const agents = [];
168→      for (const [agentType, handler] of [
169→        ["claude", getAgent("claude")],
170→        ["codex", getAgent("codex")],
171→      ] as const) {
172→        if (handler && this.initializedAgents.has(agentType)) {
173→          agents.push({
174→            type: agentType,
175→            capabilities: handler.capabilities,
176→            initialized: true,
