178→        }
179→      }
180→      return { version: "1.0", agents };
181→    });
182→
183→    // --- Initialized notification (backend confirms handshake) ---
184→    rpcTunnel.addMethod("initialized", () => {
185→      console.log("[RPC] Backend handshake complete (initialized)");
186→      return undefined;
187→    });
188→
189→    // --- turn/start (new wire protocol method, maps to query dispatch) ---
190→    rpcTunnel.addMethod("turn/start", async (params: any) => {
191→      const sessionId = params?.sessionId;
192→      const agentType = params?.agentType || "claude";
193→      const prompt = params?.prompt;
194→      const options = params?.options || {};
195→
196→      // Reject new turns during shutdown
197→      if (isShuttingDown()) {
198→        return { accepted: false, reason: "shutting down" };
199→      }
200→
201→      if (!sessionId || !prompt) {
202→        return { accepted: false, reason: "turn/start requires sessionId and prompt" };
203→      }
204→
205→      const agent = getAgent(agentType);
206→      if (!agent) {
207→        return { accepted: false, reason: `No agent registered for type: ${agentType}` };
208→      }
209→
210→      // Track this session for graceful shutdown draining
211→      trackSession(sessionId, agentType);
212→
213→      agent
214→        .query(sessionId, prompt, options)
215→        .catch((err) => {
216→          console.error(`[turn/start] Unhandled error in ${agentType} query:`, err);
217→          const classified = classifyError(err);
218→          EventBroadcaster.sendError({
219→            id: sessionId,
220→            type: "error",
221→            error: classified.message,
222→            agentType,
223→            category: classified.category,
224→          });
225→          EventBroadcaster.emitSessionError(
226→            sessionId,
227→            agentType,
228→            classified.message,
229→            classified.category
230→          );
231→        })
232→        .finally(() => {
233→          // Untrack when the turn completes (success, error, or cancel)
234→          untrackSession(sessionId);
235→        });
