253→    // --- turn/cancel (new wire protocol method, maps to cancel dispatch) ---
254→    rpcTunnel.addMethod("turn/cancel", async (params: any) => {
255→      const sessionId = params?.sessionId;
256→      if (!sessionId) return;
257→
258→      // Try all registered agents — the backend may not send agentType for cancel
