346→  /**
347→   * Handles a new WebSocket connection.
348→   * Each WS text frame is a complete JSON-RPC message (no line splitting needed).
349→   */
350→  private handleWsConnection(ws: WebSocket): void {
351→    console.log("Client connected (ws)");
352→    const transport = wsTransport(ws);
353→    const rpcTunnel = new RpcConnection(transport);
354→    this.setupJsonRpc(rpcTunnel);
355→
356→    ws.on("message", (data: Buffer | string) => {
357→      const message = typeof data === "string" ? data : data.toString("utf8");
358→      console.debug("Received WS message with length", message.length);
359→      rpcTunnel.handleMessage(message);
360→    });
361→
362→    ws.on("error", (error: Error) => {
363→      console.error("WebSocket error:", error);
364→    });
365→
366→    ws.on("close", (code: number, reason: Buffer) => {
367→      console.log(`Client disconnected (ws), code=${code} reason=${reason.toString()}`);
368→      rpcTunnel.stop();
369→      EventBroadcaster.detachTunnel(rpcTunnel);
