373→  // ==========================================================================
374→  // Lifecycle
375→  // ==========================================================================
376→
377→  /**
378→   * Kills any remaining Claude child processes spawned by this agent-server.
379→   */
380→  private async killRemainingChildProcesses(): Promise<void> {
381→    return new Promise((resolve) => {
382→      const command = `/usr/bin/pgrep -P ${process.pid}`;
383→      exec(command, (error, stdout) => {
384→        if (error) {
385→          console.log("[CLEANUP] No child processes found");
386→          resolve();
387→          return;
388→        }
389→        const childPids = stdout
390→          .trim()
391→          .split("\n")
392→          .filter((pid) => pid);
393→        if (childPids.length === 0) {
394→          console.log("[CLEANUP] No child processes to kill");
395→          resolve();
396→          return;
397→        }
398→        console.log(`[CLEANUP] Found ${childPids.length} child processes: ${childPids.join(", ")}`);
399→        childPids.forEach((pid) => {
400→          try {
401→            process.kill(Number(pid), "SIGTERM");
402→            console.log(`[CLEANUP] Sent SIGTERM to child PID ${pid}`);
403→          } catch (e) {
404→            const errorMsg = getErrorMessage(e);
405→            console.log(`[CLEANUP] Failed to kill child PID ${pid}: ${errorMsg}`);
406→          }
407→        });
408→        resolve();
409→      });
410→    });
411→  }
412→
413→  private async cleanup(): Promise<void> {
414→    await this.killRemainingChildProcesses();
415→
416→    if (this.wss) {
417→      for (const client of this.wss.clients) {
418→        client.close(1001, "Server shutting down");
419→      }
420→      this.wss.close();
421→    }
422→    if (this.httpServer) {
423→      this.httpServer.close();
424→    }
425→  }
426→
427→  /**
428→   * Starts the agent-server:
429→   * 1. Clean up stale resources
430→   * 2. Initialize agent handlers
431→   * 3. Listen on the selected transport
432→   * 4. Print connection info to stdout (consumed by the Electron main process)
433→   */
434→  async start(): Promise<void> {
435→    await this.cleanup();
436→
437→    // Register all agent handlers
438→    registerAgent(new ClaudeAgentHandler());
439→    registerAgent(new CodexAgentHandler());
440→
441→    // Initialize all registered agents
442→    console.log("Initializing agent handlers...");
443→    this.initializedAgents.clear();
444→    const initResults = initializeAllAgents();
445→    for (const [agentType, result] of initResults) {
446→      if (!result.success) {
447→        console.error(`${agentType} initialization failed:`, result.error);
448→      } else {
449→        console.log(`${agentType} handler initialized successfully`);
450→        this.initializedAgents.add(agentType);
451→      }
452→    }
453→
454→    // Mark agents as initialized for the /readyz endpoint only if at least one succeeded
455→    setAgentsInitialized(this.initializedAgents.size > 0);
456→
457→    return this.listen();
458→  }
459→
460→  private listen(): Promise<void> {
461→    return new Promise((resolve, reject) => {
462→      // Create an HTTP server for health endpoints + WS upgrade.
463→      // Binding to 127.0.0.1 — agent-server only accepts local connections.
464→      this.httpServer = createHttpServer((req, res) => {
465→        handleHttpRequest(req, res, this.wss);
466→      });
467→
468→      this.wss = new WebSocketServer({ server: this.httpServer });
469→
470→      this.wss.on("connection", (ws) => {
471→        console.log("Server: New WebSocket connection accepted");
472→        this.handleWsConnection(ws);
473→      });
474→
475→      this.wss.on("error", (error: Error) => {
476→        console.error("WebSocketServer error:", error);
477→      });
478→
479→      // Port 0 = OS-assigned dynamic port
480→      this.httpServer.listen(0, "127.0.0.1", () => {
481→        const addr = this.httpServer!.address();
482→        const port = typeof addr === "object" && addr ? addr.port : 0;
483→
484→        console.log(`Agent-server listening on ws://127.0.0.1:${port}`);
485→        console.log(`Agent-server PID: ${process.pid}`);
486→
487→        // Machine-readable output for the Electron main process / dev.sh
488→        originalLog(`LISTEN_URL=ws://127.0.0.1:${port}`);
489→        resolve();
490→      });
491→
492→      this.httpServer.on("error", (error: Error) => {
493→        console.error("HTTP server error:", error);
494→        reject(error);
495→      });
496→    });
497→  }
498→
499→}
