501→// ============================================================================
502→// Global error handlers
503→// ============================================================================
504→
505→process.on("uncaughtException", (error: any) => {
506→  console.error("Uncaught Exception:", error.message);
507→  if (error.stack) console.error("Stack:", error.stack);
508→  Sentry.captureException(error);
509→  Sentry.close(2000).finally(() => process.exit(1));
