511→
512→process.on("unhandledRejection", (reason, _promise) => {
513→  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
514→  // rejection reasons automatically. We only log here for local visibility.
515→  if (reason instanceof Error) {
