 27→export function SettingsPage() {
 28→  const activeSection = useUIStore((s) => s.activeSettingsSection);
 29→  const closeSettings = useUIStore((s) => s.closeSettings);
 30→  const { theme, setTheme } = useTheme();
 31→
 32→  const settingsQuery = useSettings();
 33→  const mcpServersQuery = useMCPServers();
 34→  const commandsQuery = useCommands();
 35→  const agentsQuery = useAgents();
 36→  const updateSettingsMutation = useUpdateSettings();
 37→
 38→  const settings = settingsQuery.data || {};
 39→  const mcpServers = mcpServersQuery.data || [];
 40→  const commands = commandsQuery.data || [];
 41→  const agents = agentsQuery.data || [];
 42→  const loading =
 43→    activeSection === "extensions"
 44→      ? settingsQuery.isLoading ||
 45→        mcpServersQuery.isLoading ||
 46→        commandsQuery.isLoading ||
 47→        agentsQuery.isLoading
 48→      : activeSection === "environment"
 49→        ? false // EnvironmentSection manages its own loading state
 50→        : settingsQuery.isLoading;
 51→  const saving = updateSettingsMutation.isPending;
 52→
 53→  // ESC closes settings
 54→  useEffect(() => {
 55→    function handleKeyDown(e: KeyboardEvent) {
 56→      if (e.key !== "Escape") return;
 57→      // Don't close if focus is in an input
 58→      const ae = document.activeElement as HTMLElement | null;
 59→      if (
 60→        ae &&
 61→        (ae.tagName === "INPUT" ||
 62→          ae.tagName === "TEXTAREA" ||
 63→          ae.isContentEditable ||
 64→          ae.getAttribute("role") === "textbox")
 65→      )
 66→        return;
 67→      closeSettings();
 68→    }
 69→
 70→    window.addEventListener("keydown", handleKeyDown);
 71→    return () => window.removeEventListener("keydown", handleKeyDown);
 72→  }, [closeSettings]);
 73→
 74→  async function saveSetting(key: string, value: unknown): Promise<boolean> {
 75→    try {
 76→      await updateSettingsMutation.mutateAsync({ [key]: value });
 77→      return true;
 78→    } catch (error) {
 79→      console.error("Failed to save setting:", error);
 80→      toast.error(`Failed to save setting: ${getErrorMessage(error)}`);
 81→      return false;
 82→    }
 83→  }
 84→
 85→  function renderContent() {
 86→    if (loading) {
 87→      return (
 88→        <div className="flex h-80 items-center justify-center">
 89→          <Loader2 className="text-muted-foreground size-5 animate-spin" />
 90→        </div>
 91→      );
 92→    }
 93→
 94→    const sectionProps = { settings, saveSetting };
 95→
 96→    return match(activeSection)
 97→      .with("general", () => <GeneralSection {...sectionProps} theme={theme} setTheme={setTheme} />)
 98→      .with("ai", () => <AISection {...sectionProps} />)
 99→      .with("extensions", () => (
100→        <ExtensionsSection mcpServers={mcpServers} commands={commands} agents={agents} />
101→      ))
102→      .with("environment", () => <EnvironmentSection />)
103→      .with("experimental", () => <ExperimentalSection {...sectionProps} />)
104→      .with("access", () => <AccessSection {...sectionProps} />)
105→      .with("updates", () => <UpdateSection />)
106→      .exhaustive();
107→  }
108→
109→  return (
110→    <SidebarInset className="min-w-0">
111→      <div className="bg-bg-surface border-border-subtle flex h-full min-w-0 flex-1 overflow-hidden rounded-xl border">
112→        <ScrollArea className="flex-1">
113→          <div className="mx-auto max-w-2xl px-8 py-8">
114→            {/* Saving indicator */}
115→            {saving && (
116→              <div className="text-muted-foreground mb-4 flex items-center gap-2 text-sm">
117→                <Loader2 className="size-3.5 animate-spin" />
118→                <span>Saving...</span>
119→              </div>
120→            )}
121→
122→            {renderContent()}
123→          </div>
124→        </ScrollArea>
125→      </div>
126→    </SidebarInset>
127→  );
128→}
