  1→import { Hono } from "hono";
  2→import type { Context } from "hono";
  3→import {
  4→  getMcpServers,
  5→  saveMcpServers,
  6→  getCommands,
  7→  saveCommand,
  8→  deleteCommand,
  9→  getAgents,
 10→  saveAgent,
 11→  deleteAgent,
 12→  getHooks,
 13→  saveHooks,
 14→  getSkills,
 15→  saveSkill,
 16→  deleteSkill,
 17→} from "../services/agent-config.service";
 18→import { ValidationError, NotFoundError } from "../lib/errors";
 19→import {
 20→  parseBody,
 21→  SaveMcpServersBody,
 22→  SaveCommandBody,
 23→  SaveAgentBody,
 24→  SaveHooksBody,
 25→  SaveSkillBody,
 26→} from "../lib/schemas";
 27→
 28→const app = new Hono();
 29→
 30→/**
 31→ * Resolve config scope from query params.
 32→ * Returns undefined for global scope, repoPath for project scope.
 33→ * Backward compatible: no params = global.
 34→ */
 35→function resolveScope(c: Context): string | undefined {
 36→  const scope = c.req.query("scope") || "global";
 37→  if (scope === "project") {
 38→    const repoPath = c.req.query("repoPath");
 39→    if (!repoPath) {
 40→      throw new ValidationError("repoPath query param required for project scope");
 41→    }
 42→    return repoPath;
 43→  }
 44→  if (scope !== "global") {
 45→    throw new ValidationError(`Invalid scope '${scope}': must be 'global' or 'project'`);
 46→  }
 47→  return undefined;
 48→}
 49→
 50→// MCP Servers
 51→app.get("/agent-config/mcp-servers", (c) => {
 52→  const projectPath = resolveScope(c);
 53→  return c.json(getMcpServers(projectPath));
 54→});
 55→
 56→app.post("/agent-config/mcp-servers", async (c) => {
 57→  const projectPath = resolveScope(c);
 58→  const { servers } = parseBody(SaveMcpServersBody, await c.req.json());
 59→  saveMcpServers(servers, projectPath);
 60→  return c.json({ success: true, servers });
 61→});
 62→
 63→// Commands
 64→app.get("/agent-config/commands", (c) => {
 65→  const projectPath = resolveScope(c);
 66→  return c.json(getCommands(projectPath));
 67→});
 68→
 69→app.post("/agent-config/commands", async (c) => {
 70→  const projectPath = resolveScope(c);
 71→  const { name, content } = parseBody(SaveCommandBody, await c.req.json());
 72→  saveCommand(name, content, projectPath);
 73→  return c.json({ success: true, name, content });
 74→});
 75→
 76→app.delete("/agent-config/commands/:name", (c) => {
 77→  const projectPath = resolveScope(c);
 78→  const found = deleteCommand(c.req.param("name"), projectPath);
 79→  if (!found) throw new NotFoundError(`Command '${c.req.param("name")}' not found`);
 80→  return c.json({ success: true });
 81→});
 82→
 83→// Agents
 84→app.get("/agent-config/agents", (c) => {
 85→  const projectPath = resolveScope(c);
 86→  return c.json(getAgents(projectPath));
 87→});
 88→
 89→app.post("/agent-config/agents", async (c) => {
 90→  const projectPath = resolveScope(c);
 91→  const { id, ...agentData } = parseBody(SaveAgentBody, await c.req.json());
 92→  saveAgent(id, agentData, projectPath);
 93→  return c.json({ success: true, id, ...agentData });
 94→});
 95→
 96→app.delete("/agent-config/agents/:id", (c) => {
 97→  const projectPath = resolveScope(c);
 98→  const found = deleteAgent(c.req.param("id"), projectPath);
 99→  if (!found) throw new NotFoundError(`Agent '${c.req.param("id")}' not found`);
100→  return c.json({ success: true });
101→});
102→
103→// Hooks
104→app.get("/agent-config/hooks", (c) => {
105→  const projectPath = resolveScope(c);
106→  return c.json(getHooks(projectPath));
107→});
108→
109→app.post("/agent-config/hooks", async (c) => {
110→  const projectPath = resolveScope(c);
111→  const { hooks } = parseBody(SaveHooksBody, await c.req.json()) as {
112→    hooks: Parameters<typeof saveHooks>[0];
113→  };
114→  saveHooks(hooks, projectPath);
115→  return c.json({ success: true, hooks });
116→});
117→
118→// Skills
119→app.get("/agent-config/skills", (c) => {
120→  const projectPath = resolveScope(c);
121→  return c.json(getSkills(projectPath));
122→});
123→
124→app.post("/agent-config/skills", async (c) => {
125→  const projectPath = resolveScope(c);
126→  const { name, content } = parseBody(SaveSkillBody, await c.req.json());
127→  saveSkill(name, content, projectPath);
128→  return c.json({ success: true, name, content });
129→});
130→
131→app.delete("/agent-config/skills/:name", (c) => {
132→  const projectPath = resolveScope(c);
133→  const found = deleteSkill(c.req.param("name"), projectPath);
134→  if (!found) throw new NotFoundError(`Skill '${c.req.param("name")}' not found`);
135→  return c.json({ success: true });
136→});
137→
