  1→// backend/src/services/agent/client.ts
  2→// WebSocket client that connects to the agent-server (agent-server).
  3→//
  4→// Implements the JSON-RPC 2.0 handshake protocol:
  5→//   Backend → Agent: { method: "initialize", params: { version: "1.0", capabilities: {} } }
  6→//   Agent → Backend: { result: { version: "1.0", agents: [...], capabilities: {} } }
  7→//   Backend → Agent: { method: "initialized" } (notification)
  8→//
  9→// After handshake, exposes typed methods for turn lifecycle and listens for
 10→// canonical agent-event notifications.
 11→
 12→import { WebSocket } from "ws";
 13→import {
 14→  JSONRPCServer,
 15→  JSONRPCClient,
 16→  JSONRPCServerAndClient,
 17→  isJSONRPCRequest,
 18→  isJSONRPCRequests,
 19→  isJSONRPCResponse,
 20→  isJSONRPCResponses,
 21→} from "json-rpc-2.0";
 22→import {
 23→  AGENT_RPC_METHODS,
 24→  AGENT_EVENT_NAMES,
 25→  FRONTEND_RPC_METHODS,
 26→  AgentEventSchema,
 27→  InitializeResultSchema,
 28→  type InitializeResult,
 29→  type TurnStartRequest,
 30→  type TurnStartResponse,
 31→  type TurnCancelRequest,
 32→  type TurnRespondRequest,
 33→  type SessionResetRequest,
 34→  type SessionStopRequest,
 35→  type ProviderAuthRequest,
 36→  type ProviderInitWorkspaceRequest,
 37→  type ProviderContextUsageRequest,
 38→  type ProviderUpdateModeRequest,
 39→  type AgentEvent,
 40→  type AgentInfo,
 41→} from "@shared/agent-events";
 42→
 43→// ============================================================================
 44→// Types
 45→// ============================================================================
 46→
 47→export type AgentEventHandler = (event: AgentEvent) => void;
 48→
 49→export interface AgentClientOptions {
 50→  /** ws://127.0.0.1:{port} — the agent-server URL */
 51→  url: string;
 52→  /** Called for every canonical agent-event notification received from the agent-server */
 53→  onEvent?: AgentEventHandler;
 54→  /** Called when the connection is established and handshake completes */
 55→  onConnected?: (agents: AgentInfo[]) => void;
 56→  /** Called when the connection drops */
 57→  onDisconnected?: () => void;
 58→  /** Called when the agent-server sends a frontend-facing RPC (browser, sim, diff, plan).
 59→   *  Must relay to the frontend and return the result. */
 60→  onFrontendRpc?: (
 61→    requestId: string,
 62→    sessionId: string,
 63→    method: string,
 64→    params: Record<string, unknown>
 65→  ) => Promise<unknown>;
 66→}
 67→
 68→// ============================================================================
 69→// Reconnect constants
 70→// ============================================================================
 71→
 72→const BASE_RECONNECT_DELAY_MS = 1_000;
 73→const MAX_RECONNECT_DELAY_MS = 30_000;
 74→const HANDSHAKE_TIMEOUT_MS = 10_000;
 75→const RPC_TIMEOUT_MS = 30_000;
 76→const PROTOCOL_VERSION = "1.0";
 77→
 78→// ============================================================================
 79→// AgentClient
 80→// ============================================================================
 81→
 82→export class AgentClient {
 83→  private url: string;
 84→  private ws: WebSocket | null = null;
 85→  private peer: JSONRPCServerAndClient | null = null;
 86→  private onEvent: AgentEventHandler;
 87→  private onConnected?: (agents: AgentInfo[]) => void;
 88→  private onDisconnected?: () => void;
 89→  private onFrontendRpc: (
 90→    requestId: string,
 91→    sessionId: string,
 92→    method: string,
 93→    params: Record<string, unknown>
 94→  ) => Promise<unknown>;
 95→
 96→  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 97→  private reconnectAttempt = 0;
 98→  private disposed = false;
 99→  private connected = false;
100→
101→  /** Agents discovered during the initialize handshake */
102→  private agents: AgentInfo[] = [];
103→
104→  constructor(options: AgentClientOptions) {
105→    this.url = options.url;
106→    this.onEvent = options.onEvent ?? (() => {});
107→    this.onConnected = options.onConnected;
108→    this.onDisconnected = options.onDisconnected;
109→    this.onFrontendRpc =
110→      options.onFrontendRpc ??
111→      (() => Promise.reject(new Error("No frontend RPC handler registered")));
112→  }
113→
114→  // ==========================================================================
115→  // Public API
116→  // ==========================================================================
117→
118→  /** Initiate connection to the agent-server. Auto-reconnects on drop. */
119→  connect(): void {
120→    if (this.disposed) return;
121→    if (this.ws && this.ws.readyState !== WebSocket.CLOSED) {
122→      return;
123→    }
124→    this.cancelReconnect();
125→    this.openConnection();
126→  }
127→
128→  /** Permanently disconnect and stop reconnecting. */
129→  disconnect(): void {
130→    this.disposed = true;
131→    this.cancelReconnect();
132→    this.closeConnection();
133→  }
134→
135→  /** Returns true if the handshake is complete and the connection is open. */
136→  isConnected(): boolean {
137→    return this.connected && this.ws?.readyState === WebSocket.OPEN;
138→  }
139→
140→  /** Returns the agents discovered during handshake. */
141→  getAgents(): ReadonlyArray<AgentInfo> {
142→    return this.agents;
143→  }
144→
145→  // ---- Turn lifecycle RPCs ----
146→
147→  async sendTurnStart(params: TurnStartRequest): Promise<TurnStartResponse> {
148→    const result = await this.request(AGENT_RPC_METHODS.TURN_START, params);
149→    if (!result || typeof result !== "object") {
150→      throw new Error("Invalid turn_start response: expected object");
151→    }
152→    return result as TurnStartResponse;
153→  }
154→
155→  async sendTurnCancel(params: TurnCancelRequest): Promise<void> {
156→    await this.request(AGENT_RPC_METHODS.TURN_CANCEL, params);
157→  }
158→
159→  async sendTurnRespond(params: TurnRespondRequest): Promise<void> {
160→    await this.request(AGENT_RPC_METHODS.TURN_RESPOND, params);
161→  }
162→
163→  // ---- Session lifecycle RPCs ----
164→
165→  async sendSessionReset(params: SessionResetRequest): Promise<void> {
166→    await this.request(AGENT_RPC_METHODS.SESSION_RESET, params);
167→  }
168→
169→  async sendSessionStop(params: SessionStopRequest): Promise<void> {
170→    await this.request(AGENT_RPC_METHODS.SESSION_STOP, params);
171→  }
172→
173→  // ---- Provider operations ----
174→
175→  async sendProviderAuth(params: ProviderAuthRequest): Promise<unknown> {
176→    return this.request(AGENT_RPC_METHODS.PROVIDER_AUTH, params);
177→  }
178→
179→  async sendProviderInitWorkspace(params: ProviderInitWorkspaceRequest): Promise<unknown> {
180→    return this.request(AGENT_RPC_METHODS.PROVIDER_INIT_WORKSPACE, params);
181→  }
182→
183→  async sendProviderContextUsage(params: ProviderContextUsageRequest): Promise<unknown> {
184→    return this.request(AGENT_RPC_METHODS.PROVIDER_CONTEXT_USAGE, params);
185→  }
186→
187→  async sendProviderUpdateMode(params: ProviderUpdateModeRequest): Promise<void> {
188→    this.notify(AGENT_RPC_METHODS.PROVIDER_UPDATE_MODE, params);
189→  }
190→
191→  // ---- Introspection ----
192→
193→  async listAgents(): Promise<AgentInfo[]> {
194→    const result = await this.request(AGENT_RPC_METHODS.AGENT_LIST, {});
195→    if (
196→      !result ||
197→      typeof result !== "object" ||
198→      !Array.isArray((result as Record<string, unknown>).agents)
199→    ) {
200→      console.error("[AgentClient] listAgents: unexpected response shape", result);
201→      return [];
202→    }
203→    return (result as Record<string, unknown>).agents as AgentInfo[];
204→  }
205→
206→  // ==========================================================================
207→  // Connection lifecycle
208→  // ==========================================================================
209→
210→  private openConnection(): void {
211→    if (this.disposed) return;
212→
213→    console.log(`[AgentClient] Connecting to ${this.url}...`);
214→
215→    try {
216→      this.ws = new WebSocket(this.url);
217→    } catch (err) {
218→      console.error("[AgentClient] Failed to create WebSocket:", err);
219→      this.scheduleReconnect();
220→      return;
221→    }
222→
223→    this.ws.on("open", () => {
224→      console.log("[AgentClient] WebSocket connected, starting handshake...");
225→      this.setupPeer();
226→      void this.performHandshake();
227→    });
228→
229→    this.ws.on("message", (data: Buffer | string) => {
230→      const message = typeof data === "string" ? data : data.toString("utf8");
231→      this.handleMessage(message);
232→    });
233→
234→    this.ws.on("close", (code, reason) => {
235→      console.log(`[AgentClient] Connection closed: ${code} ${reason.toString()}`);
236→      this.teardownPeer();
237→      if (!this.disposed) this.scheduleReconnect();
238→    });
239→
240→    this.ws.on("error", (err) => {
241→      console.error("[AgentClient] WebSocket error:", err.message);
242→    });
243→  }
244→
245→  private closeConnection(): void {
246→    if (this.ws) {
247→      this.ws.removeAllListeners();
248→      if (this.ws.readyState === WebSocket.OPEN || this.ws.readyState === WebSocket.CONNECTING) {
249→        this.ws.close(1000, "Client disconnecting");
250→      }
251→      this.ws = null;
252→    }
253→    this.teardownPeer();
254→  }
255→
256→  // ==========================================================================
257→  // JSON-RPC peer
258→  // ==========================================================================
259→
260→  private setupPeer(): void {
261→    const server = new JSONRPCServer({
262→      errorListener: (message, data) => {
263→        console.error("[AgentClient] RPC server error:", message, data);
264→      },
265→    });
266→
267→    const client = new JSONRPCClient((payload) => {
268→      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
269→        return Promise.reject(new Error("WebSocket is not open"));
270→      }
271→      try {
272→        this.ws.send(JSON.stringify(payload));
273→        return Promise.resolve();
274→      } catch (error) {
275→        return Promise.reject(error instanceof Error ? error : new Error(String(error)));
276→      }
277→    });
278→
279→    this.peer = new JSONRPCServerAndClient(server, client, {
280→      errorListener: (message, data) => {
281→        console.error("[AgentClient] RPC client error:", message, data);
282→      },
283→    });
284→
285→    // Register handlers for all agent-event notification methods.
286→    // The agent-server sends these as JSON-RPC notifications (no id).
287→    for (const eventName of Object.values(AGENT_EVENT_NAMES)) {
288→      this.peer.addMethod(eventName, async (params) => {
289→        this.dispatchEvent(eventName, params);
290→        return undefined; // notifications don't return a value
291→      });
292→    }
293→
294→    // Register handlers for frontend-facing RPC methods.
295→    // The agent-server's tools (browser, simulator, workspace) call these as
296→    // JSON-RPC requests through the tunnel. We relay them to the frontend
297→    // via tool-relay, which broadcasts a q:event tool:request and waits
298→    // for the frontend's q:tool_response.
299→    const frontendMethods = Object.values(FRONTEND_RPC_METHODS);
300→    for (const method of frontendMethods) {
301→      this.peer.addMethod(method, async (params: unknown) => {
302→        if (!params || typeof params !== "object") {
303→          throw new Error(`${method} requires an object params payload`);
304→        }
305→        const normalizedParams = params as Record<string, unknown>;
306→        const sessionId = normalizedParams.sessionId;
307→        if (typeof sessionId !== "string" || sessionId.length === 0) {
308→          throw new Error(`${method} requires params.sessionId`);
309→        }
310→        const requestId = crypto.randomUUID();
311→        console.log(
312→          `[AgentClient] Frontend RPC: method=${method} requestId=${requestId} session=${sessionId}`
313→        );
314→        const result = await this.onFrontendRpc(requestId, sessionId, method, normalizedParams);
315→        return result;
316→      });
317→    }
318→    console.log(`[AgentClient] Registered ${frontendMethods.length} frontend RPC methods`);
319→  }
320→
321→  private teardownPeer(): void {
322→    const wasConnected = this.connected;
323→    this.connected = false;
324→    this.agents = [];
325→    if (this.peer) {
326→      this.peer.rejectAllPendingRequests("Connection closed");
327→      this.peer = null;
328→    }
329→    if (wasConnected) {
330→      try {
331→        this.onDisconnected?.();
332→      } catch (err) {
333→        console.error("[AgentClient] onDisconnected callback failed:", err);
334→      }
335→    }
336→  }
337→
338→  private dispatchEvent(eventName: string, params: unknown): void {
339→    // Validate and normalize the event payload using the canonical schema.
340→    // If parsing fails, log and skip — don't crash the client.
341→    const parsed = AgentEventSchema.safeParse(params);
342→    if (!parsed.success) {
343→      console.error(
344→        `[AgentClient] Invalid event payload for "${eventName}":`,
345→        parsed.error.message
346→      );
347→      return;
348→    }
349→    if (parsed.data.type !== eventName) {
350→      console.error(
351→        `[AgentClient] Event method/type mismatch: method="${eventName}" payload.type="${parsed.data.type}"`
352→      );
353→      return;
354→    }
355→    try {
356→      this.onEvent(parsed.data);
357→    } catch (err) {
358→      console.error(`[AgentClient] Event handler threw for "${eventName}":`, err);
359→    }
360→  }
361→
362→  // ==========================================================================
363→  // Handshake
364→  // ==========================================================================
365→
366→  private async performHandshake(): Promise<void> {
367→    if (!this.peer) return;
368→
369→    try {
370→      const rawResult = await this.withTimeout(
371→        Promise.resolve(
372→          this.peer.request(AGENT_RPC_METHODS.INITIALIZE, {
373→            version: PROTOCOL_VERSION,
374→            capabilities: {},
375→          })
376→        ),
377→        HANDSHAKE_TIMEOUT_MS,
378→        "initialize"
379→      );
380→
381→      const parsed = InitializeResultSchema.safeParse(rawResult);
382→      if (!parsed.success) {
383→        throw new Error(`Invalid initialize response: ${parsed.error.message}`);
384→      }
385→      const result: InitializeResult = parsed.data;
386→
387→      if (result.version !== PROTOCOL_VERSION) {
388→        throw new Error(
389→          `Unsupported protocol version "${result.version}" (expected "${PROTOCOL_VERSION}")`
390→        );
391→      }
392→
393→      this.agents = result.agents;
394→      console.log(
395→        `[AgentClient] Handshake complete: version=${result.version} agents=[${this.agents.map((a) => a.type).join(", ")}]`
396→      );
397→
398→      // Send "initialized" notification (fire-and-forget)
399→      this.peer.notify(AGENT_RPC_METHODS.INITIALIZED, {}, undefined);
400→
401→      this.connected = true;
402→      this.reconnectAttempt = 0;
403→      try {
404→        this.onConnected?.(this.agents);
405→      } catch (err) {
406→        console.error("[AgentClient] onConnected callback failed:", err);
407→      }
408→    } catch (err) {
409→      console.error("[AgentClient] Handshake failed:", err);
410→      // Close and reconnect
411→      this.closeConnection();
412→      if (!this.disposed) this.scheduleReconnect();
413→    }
414→  }
415→
416→  // ==========================================================================
417→  // Message dispatch
418→  // ==========================================================================
419→
420→  private handleMessage(message: string): void {
421→    if (!this.peer) return;
422→
423→    let payload: unknown;
424→    try {
425→      payload = JSON.parse(message);
426→    } catch {
427→      console.error("[AgentClient] Failed to parse JSON:", message.slice(0, 200));
428→      return;
429→    }
430→
431→    if (!isJsonRpcPayload(payload)) {
432→      console.error("[AgentClient] Received non-JSON-RPC payload");
433→      return;
434→    }
435→
436→    void this.peer.receiveAndSend(payload, undefined, undefined).catch((e) => {
437→      console.error("[AgentClient] Failed to handle message:", e);
438→    });
439→  }
440→
441→  // ==========================================================================
442→  // Outbound helpers
443→  // ==========================================================================
444→
445→  private request(method: string, params: unknown): Promise<unknown> {
446→    if (!this.peer || !this.connected) {
447→      return Promise.reject(new Error(`AgentClient is not connected (method=${method})`));
448→    }
449→    return this.withTimeout(
450→      Promise.resolve(this.peer.request(method, params, undefined)),
451→      RPC_TIMEOUT_MS,
452→      method
453→    );
454→  }
455→
456→  private notify(method: string, params: unknown): void {
457→    if (!this.peer || !this.connected) {
458→      console.error(`[AgentClient] Cannot send notification "${method}" — not connected`);
459→      return;
460→    }
461→    this.peer.notify(method, params, undefined);
462→  }
463→
464→  // ==========================================================================
465→  // Reconnect
466→  // ==========================================================================
467→
468→  private scheduleReconnect(): void {
469→    if (this.reconnectTimer || this.disposed) return;
470→    const delay = Math.min(
471→      BASE_RECONNECT_DELAY_MS * 2 ** this.reconnectAttempt,
472→      MAX_RECONNECT_DELAY_MS
473→    );
474→    this.reconnectAttempt++;
475→    console.log(`[AgentClient] Reconnecting in ${delay}ms (attempt ${this.reconnectAttempt})...`);
476→    this.reconnectTimer = setTimeout(() => {
477→      this.reconnectTimer = null;
478→      this.openConnection();
479→    }, delay);
480→  }
481→
482→  private cancelReconnect(): void {
483→    if (this.reconnectTimer) {
484→      clearTimeout(this.reconnectTimer);
485→      this.reconnectTimer = null;
486→    }
487→  }
488→
489→  // ==========================================================================
490→  // Utilities
491→  // ==========================================================================
492→
493→  private withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
494→    let timerId: ReturnType<typeof setTimeout> | undefined;
495→    const timeout = new Promise<never>((_, reject) => {
496→      timerId = setTimeout(() => {
497→        reject(new Error(`[AgentClient] ${label} timed out after ${ms}ms`));
498→      }, ms);
499→    });
500→    return Promise.race([promise, timeout]).finally(() => {
501→      if (timerId !== undefined) clearTimeout(timerId);
502→    });
503→  }
504→}
505→
506→// ============================================================================
507→// JSON-RPC payload type guard
508→// ============================================================================
509→
510→function isJsonRpcPayload(payload: unknown): boolean {
511→  return (
512→    isJSONRPCRequest(payload) ||
513→    isJSONRPCRequests(payload) ||
514→    isJSONRPCResponse(payload) ||
515→    isJSONRPCResponses(payload)
516→  );
517→}
