 1→/**
 2→ * AI Provider Status Queries
 3→ *
 4→ * TanStack Query hooks that poll all registered Statuspage.io providers.
 5→ *
 6→ * Budget: N providers x (1 req / 5 min) ≈ 0.007 req/s for 2 providers.
 7→ * These are external fetches — they don't hit our backend.
 8→ */
 9→
10→import { useQueries } from "@tanstack/react-query";
11→import { queryKeys } from "@/shared/api/queryKeys";
12→import { ALL_PROVIDER_IDS, getWorstIndicator, type StatuspageIndicator } from "../lib/providers";
13→import { fetchProviderStatus, toSafeIndicator } from "./ai-status.service";
14→
15→// --- Hooks ---
16→
17→export interface ProviderStatusEntry {
18→  providerId: string;
19→  indicator: StatuspageIndicator;
20→  description: string;
21→  isLoading: boolean;
22→  isError: boolean;
23→}
24→
25→/**
26→ * Poll all registered providers in parallel.
27→ *
28→ * Uses useQueries (one query per provider) so they cache independently.
29→ * If one provider's fetch fails, the other's cached data stays valid.
30→ * Failed fetches are treated as "none" to avoid false alarms.
31→ */
32→export function useProviderStatuses() {
33→  const queries = useQueries({
34→    queries: ALL_PROVIDER_IDS.map((providerId) => ({
35→      queryKey: queryKeys.providerStatus.detail(providerId),
36→      queryFn: () => fetchProviderStatus(providerId),
37→      refetchInterval: 5 * 60 * 1000,
38→      staleTime: 4 * 60 * 1000,
39→      // refetchOnWindowFocus intentionally omitted — globally disabled
40→      // to avoid treating input focus as window focus (causes typing lag).
41→      // The 5-min refetchInterval is sufficient for status polling.
42→      retry: 1,
43→      retryDelay: 10_000,
44→    })),
45→  });
46→
47→  const statuses: ProviderStatusEntry[] = queries.map((q, i) => ({
48→    providerId: ALL_PROVIDER_IDS[i],
49→    indicator: toSafeIndicator(q.data?.status?.indicator),
50→    description: q.data?.status?.description ?? "",
51→    isLoading: q.isLoading,
52→    isError: q.isError,
53→  }));
54→
55→  const worst = getWorstIndicator(
56→    statuses.map((s) => ({ providerId: s.providerId, indicator: s.indicator }))
57→  );
58→
59→  return { statuses, worst };
60→}
