 18→    "Library/Application Support/Cursor/User/globalStorage/state.vscdb"
 19→  );
 20→  readVscdbProjects(cursorDbPath, "cursor", projects, seenPaths);
 21→
 22→  // Read from VSCode state.vscdb
 23→  const vscodeDbPath = join(
 24→    home,
 25→    "Library/Application Support/Code/User/globalStorage/state.vscdb"
 26→  );
 27→  readVscdbProjects(vscodeDbPath, "vscode", projects, seenPaths);
 28→
 29→  // Read from Claude projects directory
 30→  readClaudeProjects(join(home, ".claude/projects"), projects, seenPaths);
 31→
 32→  return c.json({ projects: projects.slice(0, 30) });
 33→});
 34→
 35→// Worktree directories created by AI coding tools — filter these from recent projects
 36→// so only root repos are shown, not individual worktree checkouts.
 37→const WORKTREE_SEGMENTS = [
 38→  "/.deus/", // Deus worktrees
 39→  "/.conductor/", // OpenDevs worktrees
 40→  "/.claude/worktrees/", // Claude Code worktrees
 41→  "/.cursor/worktrees/", // Cursor parallel agent worktrees
 42→  "/copilot-worktree/", // GitHub Copilot CLI worktrees
 43→];
 44→
 45→function isWorktreePath(fsPath: string): boolean {
 46→  return WORKTREE_SEGMENTS.some((seg) => fsPath.includes(seg));
 47→}
 48→
 49→function readVscdbProjects(
 50→  dbPath: string,
 51→  source: "cursor" | "vscode",
 52→  projects: RecentProject[],
 53→  seen: Set<string>
 54→) {
 55→  if (!existsSync(dbPath)) return;
 56→  let db: InstanceType<typeof Database> | undefined;
 57→  try {
 58→    db = new Database(dbPath, { readonly: true });
 59→    const row = db
 60→      .prepare("SELECT value FROM ItemTable WHERE key = 'history.recentlyOpenedPathsList'")
 61→      .get() as { value: string } | undefined;
 62→
 63→    if (!row?.value) return;
 64→    const data = JSON.parse(row.value);
 65→    const entries = data.entries || [];
 66→
 67→    for (const entry of entries) {
 68→      const uri = entry.folderUri;
 69→      if (!uri || !uri.startsWith("file://")) continue;
 70→      const fsPath = decodeURIComponent(uri.replace("file://", ""));
 71→      if (seen.has(fsPath) || isWorktreePath(fsPath) || !existsSync(fsPath)) continue;
 72→      seen.add(fsPath);
 73→      projects.push({ path: fsPath, name: basename(fsPath), source });
 74→    }
 75→  } catch {
 76→    // Silently skip if DB is locked or malformed
 77→  } finally {
 78→    db?.close();
 79→  }
 80→}
 81→
 82→function readClaudeProjects(dir: string, projects: RecentProject[], seen: Set<string>) {
 83→  if (!existsSync(dir)) return;
 84→  try {
 85→    const entries = readdirSync(dir, { withFileTypes: true });
 86→    for (const entry of entries) {
 87→      if (!entry.isDirectory()) continue;
 88→      // Claude encodes paths: leading dash + dashes as path separators
 89→      // e.g., "-Users-zvada-Developer-myproject" -> "/Users/zvada/Developer/myproject"
 90→      const decoded = entry.name.replace(/-/g, "/");
 91→      if (!decoded.startsWith("/")) continue;
 92→      if (seen.has(decoded) || isWorktreePath(decoded) || !existsSync(decoded)) continue;
 93→      seen.add(decoded);
 94→      projects.push({ path: decoded, name: basename(decoded), source: "claude" });
 95→    }
 96→  } catch {
 97→    // Silently skip
 98→  }
 99→}
100→
101→export default app;
102→

 1→// backend/src/routes/remote-auth.ts
 2→// Auth endpoints for remote access pairing and device management.
 3→// POST /remote-auth/pair — public, rate-limited, exchanges code for token
 4→// POST /remote-auth/generate-pair-code — localhost-only, creates a new code
 5→// GET /remote-auth/devices — localhost-only, lists paired devices
 6→// DELETE /remote-auth/devices/:id — localhost-only, revokes a device
 7→
 8→import { Hono } from "hono";
 9→import { createMiddleware } from "hono/factory";
10→import { parseBody, PairBody } from "../lib/schemas";
11→import {
12→  generatePairCode,
13→  validatePairCode,
14→  createDeviceToken,
15→  listDevices,
16→  revokeDevice,
17→  checkRateLimit,
18→  recordFailure,
19→  resetRateLimit,
20→} from "../services/remote-auth.service";
21→import { isLocalhost, getClientIp } from "../lib/network";
22→
23→const app = new Hono();
24→
25→/** Reject non-localhost requests with 403. Relay-bridged requests are trusted. */
26→const localhostOnly = createMiddleware(async (c, next) => {
27→  if (c.env?.relayBridged) {
28→    await next();
29→    return;
30→  }
31→  if (!isLocalhost(getClientIp(c))) {
32→    return c.json({ error: "This endpoint is only available from localhost" }, 403);
33→  }
34→  await next();
35→});
36→
37→// POST /remote-auth/pair — public, exchanges pairing code for device token
38→app.post("/remote-auth/pair", async (c) => {
39→  const clientIp = getClientIp(c);
40→
41→  // Rate limit check
42→  if (clientIp) {
43→    const lockout = checkRateLimit(clientIp);
44→    if (lockout > 0) {
45→      return c.json({ error: "Too many failed attempts. Try again later." }, 429);
46→    }
47→  }
48→
49→  const { code, deviceName } = parseBody(PairBody, await c.req.json());
50→
51→  if (!validatePairCode(code)) {
52→    if (clientIp) recordFailure(clientIp);
53→    return c.json({ error: "Invalid or expired connection code" }, 401);
54→  }
55→
56→  // Successful pairing — create device token
57→  if (clientIp) resetRateLimit(clientIp);
58→  const userAgent = c.req.header("user-agent") ?? null;
59→  const { token, device } = createDeviceToken(
60→    deviceName ?? "Unknown Device",
61→    clientIp ?? null,
62→    userAgent
63→  );
64→
65→  return c.json({
66→    token,
67→    device: {
68→      id: device.id,
69→      name: device.name,
70→      created_at: device.created_at,
71→    },
72→  });
73→});
74→
75→// POST /remote-auth/generate-pair-code — localhost-only
76→app.post("/remote-auth/generate-pair-code", localhostOnly, (c) => {
77→  const { code, expiresAt } = generatePairCode();
78→  const expiresInSeconds = Math.round((expiresAt - Date.now()) / 1000);
79→
80→  return c.json({ code, expires_in_seconds: expiresInSeconds });
81→});
82→
83→// GET /remote-auth/devices — localhost-only
84→app.get("/remote-auth/devices", localhostOnly, (c) => {
85→  return c.json({ devices: listDevices() });
86→});
87→
88→// DELETE /remote-auth/devices/:id — localhost-only
89→app.delete("/remote-auth/devices/:id", localhostOnly, (c) => {
90→  const id = c.req.param("id");
91→  const deleted = revokeDevice(id);
92→  if (!deleted) {
93→    return c.json({ error: "Device not found" }, 404);
94→  }
95→  return c.json({ success: true });
96→});
97→
98→export default app;
99→

  1→import { Hono } from "hono";
  2→import { cors } from "hono/cors";
  3→import { createNodeWebSocket } from "@hono/node-ws";
  4→import { errorHandler } from "./middleware/error-handler";
  5→import { remoteGateMiddleware } from "./middleware/remote-gate";
  6→import { authMiddleware } from "./middleware/remote-auth";
  7→import { validateDeviceToken } from "./services/remote-auth.service";
  8→import { addConnection, removeConnection, handleProtocolMessage } from "./services/ws.service";
  9→import { removeSubs as removeQuerySubs } from "./services/query-engine";
 10→import { getRelayStatus } from "./services/relay.service";
 11→import { isLocalhost, getClientIp } from "./lib/network";
 12→import healthRoutes from "./routes/health";
 13→import workspaceRoutes from "./routes/workspaces";
 14→import workspaceDiffRoutes from "./routes/workspaces.diff";
 15→import workspacePrRoutes from "./routes/workspaces.pr";
 16→import workspaceDesignRoutes from "./routes/workspaces.design";
 17→import sessionRoutes from "./routes/sessions";
 18→import repoRoutes from "./routes/repos";
 19→import agentConfigRoutes from "./routes/agent-config";
 20→import settingsRoutes from "./routes/settings";
 21→import statsRoutes from "./routes/stats";
 22→import onboardingRoutes from "./routes/onboarding";
 23→import authRoutes from "./routes/remote-auth";
 24→import filesRoutes from "./routes/files";
 25→export function createApp() {
 26→  const app = new Hono();
 27→  const { upgradeWebSocket, injectWebSocket } = createNodeWebSocket({ app });
 28→
 29→  // Middleware — order matters:
 30→  // 1. Remote gate rejects non-localhost when remote access is disabled
 31→  // 2. CORS headers for browser requests
 32→  // 3. Auth validates Bearer tokens for remote clients (localhost exempt)
 33→  app.use("*", remoteGateMiddleware);
 34→  app.use("*", cors());
 35→  app.use("/api/*", authMiddleware);
 36→
 37→  // Mount route groups
 38→  app.route("/api", healthRoutes);
 39→  app.route("/api", authRoutes);
 40→  app.route("/api", workspaceRoutes);
 41→  app.route("/api", workspaceDiffRoutes);
 42→  app.route("/api", workspacePrRoutes);
 43→  app.route("/api", workspaceDesignRoutes);
 44→  app.route("/api", sessionRoutes);
 45→  app.route("/api", repoRoutes);
 46→  app.route("/api", agentConfigRoutes);
 47→  app.route("/api", settingsRoutes);
 48→  app.route("/api", statsRoutes);
 49→  app.route("/api", filesRoutes);
 50→  app.route("/api", onboardingRoutes);
 51→
 52→  // Relay status endpoint
 53→  app.get("/api/relay/status", (c) => {
 54→    return c.json(getRelayStatus());
 55→  });
 56→
 57→  // WebSocket route for remote access.
 58→  // Localhost connections are auto-authenticated. Remote clients must send
 59→  // { type: "initialize", token: "..." } as their first message.
 60→  app.get(
 61→    "/ws",
 62→    upgradeWebSocket((c) => {
 63→      const ip = getClientIp(c);
 64→      const isLocal = isLocalhost(ip);
 65→      let connectionId: string | null = null;
 66→
 67→      return {
 68→        onOpen(_evt, ws) {
 69→          if (isLocal) {
 70→            // Desktop/localhost connections skip token auth
 71→            connectionId = addConnection(ws, null);
 72→            ws.send(JSON.stringify({ type: "connected", connectionId }));
 73→          }
 74→          // Remote clients stay unauthenticated until initialize message
 75→        },
 76→
 77→        onMessage(evt, ws) {
 78→          let msg: Record<string, unknown>;
 79→          try {
 80→            const raw = typeof evt.data === "string" ? evt.data : String(evt.data);
 81→            msg = JSON.parse(raw);
 82→          } catch {
 83→            return; // Ignore malformed messages
 84→          }
 85→
 86→          // Unauthenticated remote client — must initialize first
 87→          if (!connectionId) {
 88→            if (msg.type === "initialize" && typeof msg.token === "string") {
 89→              const device = validateDeviceToken(msg.token);
 90→              if (device) {
 91→                connectionId = addConnection(ws, device.id);
 92→                ws.send(JSON.stringify({ type: "connected", connectionId }));
 93→              } else {
 94→                ws.send(JSON.stringify({ type: "error", message: "Invalid token" }));
 95→                ws.close(4001, "Invalid token");
 96→              }
 97→            } else {
 98→              ws.send(
 99→                JSON.stringify({ type: "error", message: "Must send initialize with token" })
100→              );
101→              ws.close(4001, "Not authenticated");
102→            }
103→            return;
104→          }
105→
106→          // Authenticated — handle protocol messages (shared with relay virtual connections)
107→          handleProtocolMessage(connectionId, msg);
108→        },
109→
110→        onClose() {
111→          if (connectionId) {
112→            removeQuerySubs(connectionId);
113→            removeConnection(connectionId);
114→            connectionId = null;
115→          }
116→        },
117→      };
118→    })
119→  );
120→
121→  // Centralized error handling
122→  app.onError(errorHandler);
123→
124→  return { app, injectWebSocket };
125→}
