  1→import fs from "fs";
  2→import path from "path";
  3→import os from "os";
  4→import { McpConfigFile, AgentConfigFile, SettingsFile } from "../lib/schemas";
  5→import type {
  6→  SkillItem,
  7→  CommandItem,
  8→  AgentItem,
  9→  McpServerItem,
 10→  HooksMap,
