 13→const CLAUDE_DIR = path.join(os.homedir(), ".claude");
 14→const COMMANDS_DIR = path.join(CLAUDE_DIR, "commands");
 15→const AGENTS_DIR = path.join(CLAUDE_DIR, "agents");
 16→const SETTINGS_PATH = path.join(CLAUDE_DIR, "settings.json");
