 18→/**
 19→ * Resolve the .claude directory for a given scope.
 20→ * Global: ~/.claude/    Project: {projectPath}/.claude/
 21→ * Validates that projectPath is an absolute path to prevent traversal attacks.
 22→ */
 23→export function resolveClaudeDir(projectPath?: string): string {
 24→  if (!projectPath) return CLAUDE_DIR;
 25→  if (!path.isAbsolute(projectPath)) {
 26→    throw new Error("projectPath must be an absolute path");
 27→  }
 28→  return path.join(projectPath, ".claude");
 29→}
 30→
 31→function sanitizeName(name: string): string {
 32→  if (!name || !/^[a-zA-Z0-9_-]+$/.test(name)) {
 33→    throw new Error("Invalid name: must be alphanumeric, hyphens, or underscores only");
 34→  }
 35→  return name;
 36→}
 37→
 38→function ensureDirectories(): void {
 39→  const dirs = [CLAUDE_DIR, path.join(CLAUDE_DIR, "plugins"), COMMANDS_DIR, AGENTS_DIR];
 40→  dirs.forEach((dir) => {
 41→    if (!fs.existsSync(dir)) {
 42→      fs.mkdirSync(dir, { recursive: true });
 43→    }
 44→  });
 45→}
 46→
 47→// Initialize global directories on module load
 48→ensureDirectories();
