 50→// ============================================================================
 51→// MCP Servers
 52→// ============================================================================
 53→
 54→export function getMcpServers(projectPath?: string): McpServerItem[] {
 55→  const configPath = path.join(resolveClaudeDir(projectPath), "plugins", "config.json");
 56→  if (!fs.existsSync(configPath)) return [];
 57→
 58→  let raw: unknown;
 59→  try {
 60→    raw = JSON.parse(fs.readFileSync(configPath, "utf8"));
 61→  } catch {
 62→    console.error("Failed to parse MCP config file as JSON");
 63→    return [];
 64→  }
 65→
 66→  const parsed = McpConfigFile.safeParse(raw);
 67→  if (!parsed.success) {
 68→    console.error("Invalid MCP config file:", parsed.error.issues);
 69→    return [];
 70→  }
 71→
 72→  return Object.entries(parsed.data.mcpServers).map(([name, entry]) => ({
 73→    name,
 74→    command: entry.command,
 75→    args: entry.args,
 76→    env: entry.env,
 77→  }));
 78→}
 79→
 80→export function saveMcpServers(
 81→  servers: Array<{ name: string; command: string; args?: string[]; env?: Record<string, string> }>,
 82→  projectPath?: string
 83→): void {
 84→  const configPath = path.join(resolveClaudeDir(projectPath), "plugins", "config.json");
 85→  const configDir = path.dirname(configPath);
 86→  if (!fs.existsSync(configDir)) {
 87→    fs.mkdirSync(configDir, { recursive: true });
 88→  }
 89→
 90→  // Read existing config to preserve non-mcpServers keys
 91→  let existing: Record<string, unknown> = {};
 92→  if (fs.existsSync(configPath)) {
 93→    try {
 94→      const parsed = JSON.parse(fs.readFileSync(configPath, "utf8"));
 95→      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
 96→        existing = parsed as Record<string, unknown>;
 97→      }
 98→    } catch {
 99→      // Corrupted config — start fresh
100→      console.error("Failed to parse existing MCP config, starting fresh");
101→    }
102→  }
103→
104→  const mcpServers: Record<
105→    string,
106→    { command: string; args: string[]; env: Record<string, string> }
107→  > = {};
108→  servers.forEach((server) => {
109→    mcpServers[server.name] = {
110→      command: server.command,
111→      args: server.args || [],
112→      env: server.env || {},
113→    };
114→  });
115→
116→  fs.writeFileSync(configPath, JSON.stringify({ ...existing, mcpServers }, null, 2));
117→}
