240→export function saveHooks(hooks: HooksMap, projectPath?: string): void {
241→  const settingsPath = path.join(resolveClaudeDir(projectPath), "settings.json");
242→  let settings: Record<string, unknown> = {};
243→  if (fs.existsSync(settingsPath)) {
244→    try {
245→      const parsed = JSON.parse(fs.readFileSync(settingsPath, "utf8"));
246→      // Only use parsed result if it's a plain object — arrays, strings, etc. are not valid settings
247→      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
248→        settings = parsed as Record<string, unknown>;
249→      } else {
250→        console.error("settings.json is not a valid object, starting with empty settings");
251→      }
