 46→  // Validate pagination: clamp limit to 1-500, reject non-positive cursors
 47→  const rawLimit = Number(c.req.query("limit"));
 48→  const limit = Math.max(1, Math.min(Number.isFinite(rawLimit) ? rawLimit : 50, 500));
 49→  // Pagination uses seq (integer), not sent_at (string with collisions)
 50→  const beforeParsed = parseInt(c.req.query("before") ?? "", 10);
 51→  const afterParsed = parseInt(c.req.query("after") ?? "", 10);
 52→  const before = Number.isFinite(beforeParsed) && beforeParsed >= 1 ? beforeParsed : undefined;
 53→  const after = Number.isFinite(afterParsed) && afterParsed >= 1 ? afterParsed : undefined;
 54→
 55→  const messages = getMessages(db, sessionId, { limit, before, after });
 56→
 57→  // Check if there are older/newer messages using seq boundaries
 58→  const oldestSeq = messages.length > 0 ? messages[0].seq : null;
 59→  const newestSeq = messages.length > 0 ? messages[messages.length - 1].seq : null;
 60→
 61→  const has_older = oldestSeq != null ? hasOlderMessages(db, sessionId, oldestSeq) : false;
 62→  const has_newer = newestSeq != null ? hasNewerMessages(db, sessionId, newestSeq) : false;
