  2→// Composition root for agent-server communication.
  3→//
  4→// Creates the AgentClient, wires the event handler with injected dependencies,
  5→// and exposes typed methods for other services to call. No circular imports —
  6→// this module imports from its dependencies, none of them import back.
  7→//
  8→// Dependency graph (all arrows point down, no cycles):
  9→//
 10→//   service (this file)
 11→//       ├── client              (WebSocket transport)
 12→//       ├── event-handler       (factory: createAgentEventHandler)
 13→//       └── tool-relay          (frontend RPC relay)
 14→//
 15→// Initialized once at startup in server.ts via agentService.init().
 16→
 17→import { AgentClient } from "./client";
 18→import { createAgentEventHandler } from "./event-handler";
 19→import { relay } from "./tool-relay";
 20→import {
 21→  persistSessionNeedsPlanResponse,
 22→  persistSessionNeedsResponse,
 23→  persistSessionBackToWorking,
 24→} from "./persistence";
 25→import { invalidate } from "../query-engine";
 26→import type {
 27→  TurnStartRequest,
 28→  TurnStartResponse,
 29→  TurnRespondRequest,
 30→  SessionStopRequest,
 31→} from "@shared/agent-events";
 32→
 33→// ---- Singleton ----
 34→
 35→let client: AgentClient | null = null;
 36→
 37→/** Initialize the agent service. Call once at startup. */
 38→export function init(agentServerUrl: string): void {
 39→  if (client) {
 40→    console.warn("[AgentService] Already initialized, skipping");
 41→    return;
 42→  }
 43→
 44→  client = new AgentClient({
 45→    url: agentServerUrl,
 46→
 47→    // Wire the event handler with respondToAgent injected — breaks the
 48→    // circular dependency that previously existed between these modules.
 49→    onEvent: createAgentEventHandler({
 50→      respondToAgent: (params) => respondToAgent(params),
 51→    }),
 52→
 53→    onConnected: (agents) => {
 54→      console.log(`[AgentService] Connected, agents: [${agents.map((a) => a.type).join(", ")}]`);
 55→    },
 56→    onDisconnected: () => {
 57→      console.log("[AgentService] Disconnected from agent-server");
 58→    },
 59→
 60→    // Relay agent-server's frontend-facing RPC requests (browser, sim, diff, plan)
 61→    onFrontendRpc: async (requestId, sessionId, method, params) => {
 62→      const isUserFacing = method === "exitPlanMode" || method === "askUserQuestion";
 63→      const sessionResources = ["workspaces", "sessions", "session", "stats"] as const;
 64→
 65→      // User-facing methods: update session status so sidebar shows "needs input" instead of "working"
 66→      if (method === "exitPlanMode") {
 67→        const result = persistSessionNeedsPlanResponse(sessionId);
 68→        if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 69→      } else if (method === "askUserQuestion") {
 70→        const result = persistSessionNeedsResponse(sessionId);
 71→        if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 72→      }
 73→
 74→      try {
 75→        return await relay({
 76→          type: "tool.request",
 77→          requestId,
 78→          sessionId,
 79→          method,
 80→          params,
 81→          // User-facing methods wait indefinitely; auto-responding keep 2-min timeout
 82→          timeoutMs: isUserFacing ? 24 * 60 * 60 * 1000 : 120_000,
 83→        });
 84→      } finally {
 85→        if (isUserFacing) {
 86→          const result = persistSessionBackToWorking(sessionId);
 87→          if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 88→        }
 89→      }
 90→    },
 91→  });
 92→
 93→  client.connect();
 94→}
 95→
 96→/** Gracefully shut down the agent client. */
 97→export function shutdown(): void {
 98→  client?.disconnect();
 99→  client = null;
100→}
