 43→// ============================================================================
 44→// Logging
 45→// ============================================================================
 46→
 47→export const logFilePath = `/tmp/deus-${process.pid}.log`;
 48→const originalLog = console.log;
 49→
 50→const LOG_LEVEL = (process.env.LOG_LEVEL || "info") as "debug" | "info" | "error";
 51→const LOG_LEVELS = { debug: 0, info: 1, error: 2 };
 52→
 53→function shouldLog(level: "debug" | "info" | "error"): boolean {
 54→  return LOG_LEVELS[level] >= LOG_LEVELS[LOG_LEVEL];
 55→}
 56→
 57→function formatLogArgs(args: any[]): string {
 58→  return args
 59→    .map((arg) => {
 60→      if (typeof arg === "string") return arg;
 61→      if (arg instanceof Error) return `${arg.message}\n${arg.stack || ""}`;
 62→      return util.inspect(arg, { depth: 4, breakLength: Infinity });
 63→    })
 64→    .join(" ");
 65→}
 66→
 67→// Buffered log writer -- avoids synchronous appendFileSync on every log call
 68→let logBuffer = "";
 69→let flushTimer: NodeJS.Timeout | null = null;
 70→
 71→function flushLogs(): void {
 72→  if (logBuffer) {
 73→    fs.appendFileSync(logFilePath, logBuffer);
 74→    logBuffer = "";
 75→  }
 76→  flushTimer = null;
 77→}
 78→
 79→function writeLog(line: string): void {
 80→  logBuffer += line;
 81→  if (!flushTimer) {
 82→    flushTimer = setTimeout(flushLogs, 100);
 83→  }
 84→  if (logBuffer.length > 8192) {
 85→    flushLogs();
 86→  }
 87→}
 88→
 89→// Ensure logs are flushed on shutdown
 90→process.on("exit", flushLogs);
 91→
 92→console.log = (...args: any[]) => {
 93→  if (!shouldLog("info")) return;
 94→  const timestamp = new Date().toISOString();
 95→  writeLog(`[${timestamp}] ${formatLogArgs(args)}\n`);
 96→};
 97→
 98→console.error = (...args: any[]) => {
 99→  const timestamp = new Date().toISOString();
100→  writeLog(`[${timestamp}] ERROR: ${formatLogArgs(args)}\n`);
101→};
102→
103→console.debug = (...args: any[]) => {
104→  if (!shouldLog("debug")) return;
105→  const timestamp = new Date().toISOString();
106→  writeLog(`[${timestamp}] DEBUG: ${formatLogArgs(args)}\n`);
107→};
