110→// AgentServer
111→// ============================================================================
112→
113→class AgentServer {
114→  private initializedAgents = new Set<string>();
115→  private httpServer: ReturnType<typeof createHttpServer> | null = null;
116→  private wss: WebSocketServer | null = null;
117→
118→  constructor() {
119→    console.log("AgentServer: Initializing...");
120→
121→    // Graceful shutdown handlers — drain in-flight turns before exiting
122→    const gracefulShutdown = async (signal: string) => {
123→      console.log(`\n[SIGNAL] Received ${signal}, shutting down gracefully...`);
124→
125→      // 1. Stop accepting new turn/start requests
126→      setShuttingDown(true);
127→
128→      // 2. Stop accepting new WS connections (close the HTTP listener)
129→      if (this.httpServer) {
130→        this.httpServer.close();
131→        console.log("[SHUTDOWN] HTTP server closed to new connections");
132→      }
133→
134→      // 3. Wait for in-flight turns to drain (default 30s timeout)
135→      console.log("[SHUTDOWN] Waiting for in-flight turns to drain...");
136→      const drained = await waitForDrain();
137→      if (drained) {
138→        console.log("[SHUTDOWN] All turns drained successfully");
139→      } else {
140→        console.log("[SHUTDOWN] Drain timeout reached, cancelling remaining sessions");
141→        await cancelRemainingSessions();
142→      }
143→
144→      // 4. Full cleanup (kill child processes, close WS clients)
145→      try {
146→        await this.cleanup();
147→        console.log("[SIGNAL] Cleanup complete, exiting process");
148→      } catch (error) {
149→        console.error("[SIGNAL] Cleanup failed:", error);
150→      } finally {
151→        process.exit(0);
152→      }
153→    };
154→    process.on("SIGINT", () => gracefulShutdown("SIGINT"));
155→    process.on("SIGTERM", () => gracefulShutdown("SIGTERM"));
156→  }
157→
158→  /**
159→   * Wires up all JSON-RPC methods and notifications on a new connection.
160→   */
161→  private setupJsonRpc(rpcTunnel: RpcConnection): void {
162→    EventBroadcaster.attachTunnel(rpcTunnel);
163→
164→    // --- Initialize handshake (backend agent-client sends this) ---
165→    rpcTunnel.addMethod("initialize", () => {
166→      const agents = [];
167→      for (const [agentType, handler] of [
168→        ["claude", getAgent("claude")],
169→        ["codex", getAgent("codex")],
170→      ] as const) {
171→        if (handler && this.initializedAgents.has(agentType)) {
172→          agents.push({
173→            type: agentType,
174→            capabilities: handler.capabilities,
175→            initialized: true,
176→          });
177→        }
178→      }
179→      return { version: "1.0", agents };
180→    });
181→
182→    // --- Initialized notification (backend confirms handshake) ---
183→    rpcTunnel.addMethod("initialized", () => {
184→      console.log("[RPC] Backend handshake complete (initialized)");
185→      return undefined;
186→    });
187→
188→    // --- turn/start (new wire protocol method, maps to query dispatch) ---
189→    rpcTunnel.addMethod("turn/start", async (params: any) => {
190→      const sessionId = params?.sessionId;
191→      const agentType = params?.agentType || "claude";
192→      const prompt = params?.prompt;
193→      const options = params?.options || {};
194→
195→      // Reject new turns during shutdown
196→      if (isShuttingDown()) {
197→        return { accepted: false, reason: "shutting down" };
198→      }
199→
200→      if (!sessionId || !prompt) {
201→        return { accepted: false, reason: "turn/start requires sessionId and prompt" };
202→      }
203→
204→      const agent = getAgent(agentType);
205→      if (!agent) {
206→        return { accepted: false, reason: `No agent registered for type: ${agentType}` };
207→      }
208→
209→      // Track this session for graceful shutdown draining
210→      trackSession(sessionId, agentType);
211→
212→      agent
213→        .query(sessionId, prompt, options)
214→        .catch((err) => {
215→          console.error(`[turn/start] Unhandled error in ${agentType} query:`, err);
216→          const classified = classifyError(err);
217→          EventBroadcaster.sendError({
218→            id: sessionId,
219→            type: "error",
220→            error: classified.message,
221→            agentType,
222→            category: classified.category,
223→          });
224→          EventBroadcaster.emitSessionError(
225→            sessionId,
226→            agentType,
227→            classified.message,
228→            classified.category
229→          );
230→        })
231→        .finally(() => {
232→          // Untrack when the turn completes (success, error, or cancel)
233→          untrackSession(sessionId);
234→        });
235→
236→      EventBroadcaster.emitSessionStarted(sessionId, agentType);
237→
238→      console.log(`[TIMING][turn/start] DISPATCHED session=${sessionId}`);
239→      return { accepted: true };
240→    });
241→
242→    // --- turn/respond (tool relay response from backend) ---
243→    // Currently a stub: the agent-server tools use direct JSON-RPC requests
244→    // (EventBroadcaster.requestBrowserXxx) rather than the canonical
245→    // tool.request notification path. When tools migrate to the canonical
246→    // path, this handler will resolve pending promises by requestId.
247→    rpcTunnel.addMethod("turn/respond", (params: any) => {
248→      const { requestId } = params ?? {};
249→      console.log(`[AgentServer] turn/respond received (requestId=${requestId})`);
250→    });
251→
252→    // --- turn/cancel (new wire protocol method, maps to cancel dispatch) ---
253→    rpcTunnel.addMethod("turn/cancel", async (params: any) => {
254→      const sessionId = params?.sessionId;
255→      if (!sessionId) return;
256→
257→      // Try all registered agents — the backend may not send agentType for cancel
258→      for (const agentType of ["claude", "codex"] as const) {
259→        const agent = getAgent(agentType);
260→        if (agent) void agent.cancel(sessionId);
261→      }
262→    });
263→
264→    // --- session/reset (new wire protocol method) ---
265→    rpcTunnel.addMethod("session/reset", (params: any) => {
266→      const sessionId = params?.sessionId;
267→      if (!sessionId) return;
268→
269→      for (const agentType of ["claude", "codex"] as const) {
270→        const agent = getAgent(agentType);
271→        if (agent) agent.reset(sessionId);
272→      }
273→    });
274→
275→    // --- session/stop (stop a running session) ---
276→    rpcTunnel.addMethod("session/stop", async (params: any) => {
277→      const sessionId = params?.sessionId;
278→      if (!sessionId) return;
279→
280→      for (const agentType of ["claude", "codex"] as const) {
281→        const agent = getAgent(agentType);
282→        if (agent) void agent.cancel(sessionId);
283→      }
284→    });
285→
286→    // --- provider/auth (check agent authentication) ---
287→    rpcTunnel.addMethod("provider/auth", async (params: any) => {
288→      const agentType = params?.agentType || "claude";
289→      const agent = getAgent(agentType);
290→      if (!agent?.auth) throw new Error(`Agent "${agentType}" does not support auth`);
291→      return agent.auth({ cwd: params?.cwd });
292→    });
293→
294→    // --- provider/initWorkspace (slash commands, MCP servers) ---
295→    rpcTunnel.addMethod("provider/initWorkspace", async (params: any) => {
296→      const agentType = params?.agentType || "claude";
297→      const agent = getAgent(agentType);
298→      if (!agent?.initWorkspace)
299→        throw new Error(`Agent "${agentType}" does not support workspace init`);
300→      return agent.initWorkspace({
301→        cwd: params?.cwd,
302→        ghToken: params?.ghToken,
303→        providerEnvVars: params?.providerEnvVars,
304→      });
305→    });
306→
307→    // --- provider/contextUsage (token usage stats) ---
308→    rpcTunnel.addMethod("provider/contextUsage", async (params: any) => {
309→      const agentType = params?.agentType || "claude";
310→      const agent = getAgent(agentType);
311→      if (!agent?.getContextUsage)
312→        throw new Error(`Agent "${agentType}" does not support context usage`);
313→      return agent.getContextUsage({
314→        options: {
315→          cwd: params?.cwd ?? "",
316→          agentSessionId: params?.agentSessionId ?? "",
317→        },
318→      });
319→    });
320→
321→    // --- provider/updateMode (runtime permission mode change) ---
322→    rpcTunnel.addMethod("provider/updateMode", (params: any) => {
323→      const agentType = params?.agentType || "claude";
324→      const agent = getAgent(agentType);
325→      if (agent?.updatePermissionMode) {
326→        void agent.updatePermissionMode(params?.sessionId, params?.permissionMode);
327→      }
328→    });
329→
330→    // --- agent/list (introspection: list available agents) ---
331→    rpcTunnel.addMethod("agent/list", () => {
332→      const agents = [];
333→      for (const [agentType, handler] of [
334→        ["claude", getAgent("claude")],
335→        ["codex", getAgent("codex")],
336→      ] as const) {
337→        if (handler && this.initializedAgents.has(agentType)) {
338→          agents.push({ type: agentType, capabilities: handler.capabilities });
339→        }
340→      }
341→      return { agents };
342→    });
343→  }
