345→  /**
346→   * Handles a new WebSocket connection.
347→   * Each WS text frame is a complete JSON-RPC message (no line splitting needed).
348→   */
349→  private handleWsConnection(ws: WebSocket): void {
350→    console.log("Client connected (ws)");
351→    const transport = wsTransport(ws);
352→    const rpcTunnel = new RpcConnection(transport);
353→    this.setupJsonRpc(rpcTunnel);
354→
355→    ws.on("message", (data: Buffer | string) => {
356→      const message = typeof data === "string" ? data : data.toString("utf8");
357→      console.debug("Received WS message with length", message.length);
358→      rpcTunnel.handleMessage(message);
359→    });
360→
361→    ws.on("error", (error: Error) => {
362→      console.error("WebSocket error:", error);
363→    });
364→
365→    ws.on("close", (code: number, reason: Buffer) => {
366→      console.log(`Client disconnected (ws), code=${code} reason=${reason.toString()}`);
367→      rpcTunnel.stop();
368→      EventBroadcaster.detachTunnel(rpcTunnel);
369→    });
