376→  /**
377→   * Kills any remaining Claude child processes spawned by this agent-server.
378→   */
379→  private async killRemainingChildProcesses(): Promise<void> {
380→    return new Promise((resolve) => {
381→      const command = `/usr/bin/pgrep -P ${process.pid}`;
382→      exec(command, (error, stdout) => {
383→        if (error) {
384→          console.log("[CLEANUP] No child processes found");
385→          resolve();
386→          return;
387→        }
388→        const childPids = stdout
389→          .trim()
390→          .split("\n")
391→          .filter((pid) => pid);
392→        if (childPids.length === 0) {
393→          console.log("[CLEANUP] No child processes to kill");
394→          resolve();
395→          return;
396→        }
397→        console.log(`[CLEANUP] Found ${childPids.length} child processes: ${childPids.join(", ")}`);
398→        childPids.forEach((pid) => {
399→          try {
400→            process.kill(Number(pid), "SIGTERM");
401→            console.log(`[CLEANUP] Sent SIGTERM to child PID ${pid}`);
402→          } catch (e) {
403→            const errorMsg = getErrorMessage(e);
404→            console.log(`[CLEANUP] Failed to kill child PID ${pid}: ${errorMsg}`);
405→          }
406→        });
407→        resolve();
408→      });
409→    });
410→  }
411→
412→  private async cleanup(): Promise<void> {
413→    await this.killRemainingChildProcesses();
414→
415→    if (this.wss) {
416→      for (const client of this.wss.clients) {
417→        client.close(1001, "Server shutting down");
418→      }
419→      this.wss.close();
420→    }
421→    if (this.httpServer) {
422→      this.httpServer.close();
423→    }
424→  }
