426→  /**
427→   * Starts the agent-server:
428→   * 1. Clean up stale resources
429→   * 2. Initialize agent handlers
430→   * 3. Listen on the selected transport
431→   * 4. Print connection info to stdout (consumed by the Electron main process)
432→   */
433→  async start(): Promise<void> {
434→    await this.cleanup();
435→
436→    // Register all agent handlers
437→    registerAgent(new ClaudeAgentHandler());
438→    registerAgent(new CodexAgentHandler());
439→
440→    // Initialize all registered agents
441→    console.log("Initializing agent handlers...");
442→    this.initializedAgents.clear();
443→    const initResults = initializeAllAgents();
444→    for (const [agentType, result] of initResults) {
445→      if (!result.success) {
446→        console.error(`${agentType} initialization failed:`, result.error);
447→      } else {
448→        console.log(`${agentType} handler initialized successfully`);
449→        this.initializedAgents.add(agentType);
450→      }
451→    }
452→
453→    // Mark agents as initialized for the /readyz endpoint only if at least one succeeded
454→    setAgentsInitialized(this.initializedAgents.size > 0);
455→
456→    return this.listen();
457→  }
458→
459→  private listen(): Promise<void> {
460→    return new Promise((resolve, reject) => {
461→      // Create an HTTP server for health endpoints + WS upgrade.
462→      // Binding to 127.0.0.1 — agent-server only accepts local connections.
463→      this.httpServer = createHttpServer((req, res) => {
464→        handleHttpRequest(req, res, this.wss);
465→      });
466→
467→      this.wss = new WebSocketServer({ server: this.httpServer });
468→
469→      this.wss.on("connection", (ws) => {
470→        console.log("Server: New WebSocket connection accepted");
471→        this.handleWsConnection(ws);
472→      });
473→
474→      this.wss.on("error", (error: Error) => {
475→        console.error("WebSocketServer error:", error);
476→      });
477→
478→      // Port 0 = OS-assigned dynamic port
479→      this.httpServer.listen(0, "127.0.0.1", () => {
480→        const addr = this.httpServer!.address();
481→        const port = typeof addr === "object" && addr ? addr.port : 0;
482→
483→        console.log(`Agent-server listening on ws://127.0.0.1:${port}`);
484→        console.log(`Agent-server PID: ${process.pid}`);
485→
486→        // Machine-readable output for the Electron main process / dev.sh
487→        originalLog(`LISTEN_URL=ws://127.0.0.1:${port}`);
488→        resolve();
489→      });
490→
491→      this.httpServer.on("error", (error: Error) => {
492→        console.error("HTTP server error:", error);
493→        reject(error);
494→      });
495→    });
496→  }
497→
498→}
