  const codexInstalled = agents.find((a) => a.type === "codex")?.installed;
  const claudeConnected = claudeAuth && !claudeAuth.error && claudeAuth.accountInfo;
  const codexConnected = codexAuth && !codexAuth.error && codexAuth.accountInfo;

