              <p className="text-muted-foreground mt-0.5 text-xs">
                {claudeAuth.accountInfo.email}
                {claudeAuth.accountInfo.orgName ? ` · ${claudeAuth.accountInfo.orgName}` : ""}
              </p>
            )}
          </div>
          <div className="flex items-center gap-2">
            <AuthBadge auth={claudeAuth} installed={claudeInstalled} isLoading={agentAuthQuery.isLoading} />
            {!agentAuthQuery.isLoading && claudeInstalled === false && (
              <Button
                variant="outline"
                size="sm"
                className="h-7 gap-1.5 text-xs"
                onClick={() => window.open("https://docs.anthropic.com/en/docs/claude-code/overview", "_blank")}
              >
                Install
                <ExternalLink className="size-3" />
              </Button>
            )}
            {!agentAuthQuery.isLoading && claudeInstalled && !claudeConnected && (
              <Button
