                onClick={() => {
                  navigator.clipboard.writeText("claude login");
                  toast.success("Copied to clipboard", {
                    description: "Run claude login in your terminal",
                  });
                }}
              >
                <Terminal className="size-3" />
                claude login
                <Copy className="size-3 opacity-50" />
              </Button>
            )}
