          <div>
            <p className="text-sm font-medium">Claude Code</p>
            <p className="text-muted-foreground text-sm">Anthropic</p>
            {claudeConnected && claudeAuth?.accountInfo?.email && (
              <p className="text-muted-foreground mt-0.5 text-xs">
