async function resolveIconFileName(appPath: string): Promise<string> {
  try {
    const { stdout } = await execFileAsync("/usr/libexec/PlistBuddy", [
      "-c",
      "Print :CFBundleIconFile",
      `${appPath}/Contents/Info.plist`,
    ]);
    const name = stdout.trim();
