  repositoryId: string,
  options?: {
    source_branch?: string;
    pr_number?: number;
    pr_url?: string;
    pr_title?: string;
    target_branch?: string;
  }
): Promise<Workspace> => {
  const result = await sendCommand("createWorkspace", {
    repository_id: repositoryId,
    ...options,
  });
  if (!result.accepted) throw new Error(result.error || "Failed to create workspace");
  // Command ack returns workspace ID as commandId — construct minimal
  // workspace object for callers that need id + repository_id.
  return { id: result.commandId, repository_id: repositoryId } as Workspace;
},

/**
 * Update workspace (e.g., archive)
 */
update: async (id: string, data: Partial<Workspace>): Promise<Workspace> => {
  const result = await sendMutate<Workspace>("updateWorkspace", { workspaceId: id, ...data });
  if (!result.success) throw new Error(result.error || "Failed to update workspace");

